INSERT INTO departments VALUES(1,'Medicine','medicine','Your journey to better health begins with the right diagnosis and the right doctor.','The Medicine Department at AMZ Hospital Ltd. provides comprehensive, patient-centered care for a wide range of acute and chronic medical conditions. Our experienced physicians specialize in the prevention, diagnosis, and treatment of diseases affecting multiple organ systems, ensuring a holistic approach to patient well-being. With advanced diagnostic support, evidence-based treatment protocols, and a strong focus on early detection, we are committed to delivering safe, efficient, and compassionate care tailored to each individual''s needs.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 220px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Medicine</h2>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">The Medicine Department at AMZ Hospital Ltd. provides comprehensive, patient-centered care for a wide range of acute and chronic medical conditions. Our experienced physicians specialize in the prevention, diagnosis, and treatment of diseases affecting multiple organ systems, ensuring a holistic approach to patient well-being. With advanced diagnostic support, evidence-based treatment protocols, and a strong focus on early detection, we are committed to delivering safe, efficient, and compassionate care tailored to each individual’s needs.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>General adult health check-ups, management of diabetes, hypertension, lipid disorders</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Diagnostic services: ECG, echocardiography, pulmonary function tests, blood work, imaging coordination</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Chronic disease management and lifestyle counseling</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Hypertension, diabetes, cardiovascular risk factors</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Infectious diseases (respiratory, GI, urinary)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Pulmonary conditions, endocrine and metabolic disorders</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="medicineFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="mf1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#medCollapse1" aria-expanded="true" aria-controls="medCollapse1"> How to book a consultation with Medicine? </button></h6>\r\n</div>\r\n<div id="medCollapse1" class="collapse" aria-labelledby="mf1" data-parent="#medicineFaqAccordion">\r\n<div class="card-body text-dark">Appointments can be booked via our website, call center, or in-person at the outpatient department.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="mf2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#medCollapse2" aria-expanded="false" aria-controls="medCollapse2"> What investigations are commonly advised? </button></h6>\r\n</div>\r\n<div id="medCollapse2" class="collapse" aria-labelledby="mf2" data-parent="#medicineFaqAccordion">\r\n<div class="card-body text-dark">Common investigations include ECG, blood tests, imaging studies, and other disease-specific diagnostic tests.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="mf3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#medCollapse3" aria-expanded="false" aria-controls="medCollapse3"> Insurance/payment options and referrals? </button></h6>\r\n</div>\r\n<div id="medCollapse3" class="collapse" aria-labelledby="mf3" data-parent="#medicineFaqAccordion">\r\n<div class="card-body text-dark">AMZ Hospital accepts major insurance plans; referrals can be coordinated by our staff as needed.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="mf4" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#medCollapse4" aria-expanded="false" aria-controls="medCollapse4"> Visiting hours and outpatient protocols? </button></h6>\r\n</div>\r\n<div id="medCollapse4" class="collapse" aria-labelledby="mf4" data-parent="#medicineFaqAccordion">\r\n<div class="card-body text-dark">Visiting hours are available on our website; outpatient protocols follow scheduled appointments with safety guidelines.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap JS dependencies -->','\r',char(13)),'\n',char(10)),1,1,'fa-user-doctor','bg-emerald-50','text-emerald-100','from-emerald-500 to-teal-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 11:33:25','<ul><li>General adult health check-ups, management of diabetes, hypertension, lipid disorders</li><li>Diagnostic services: ECG, echocardiography, pulmonary function tests, blood work, imaging coordination</li><li>Chronic disease management and lifestyle counseling</li></ul>','<ul><li>Hypertension, diabetes, cardiovascular risk factors</li><li>Infectious diseases (respiratory, GI, urinary)</li><li>Pulmonary conditions, endocrine and metabolic disorders</li></ul>','',NULL,NULL,'[{"question":"How to book a consultation with Medicine?","answer":"Appointments can be booked via our website, call center, or in-person at the outpatient department."},{"question":"What investigations are commonly advised?","answer":"Common investigations include ECG, blood tests, imaging studies, and other disease-specific diagnostic tests."},{"question":"Insurance/payment options and referrals?","answer":"AMZ Hospital accepts major insurance plans; referrals can be coordinated by our staff as needed."},{"question":"Visiting hours and outpatient protocols?","answer":"Visiting hours are available on our website; outpatient protocols follow scheduled appointments with safety guidelines."}]');
INSERT INTO departments VALUES(2,'Oncology','oncology','“‘We don’t just treat cancer — we heal the person, their family, and their hope.’”','The Oncology Department offers comprehensive cancer care, from early detection and diagnosis to treatment and long-term follow-up. Multidisciplinary teams design personalized care plans using advanced therapies.',replace(replace('<div class="container my-5">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f4f7f9, #e8f1f0, #dfe6f0); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Oncology</h2>\r\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;</p>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #111;">The Oncology Department offers comprehensive cancer care, from early detection and diagnosis to treatment and long-term follow-up. Multidisciplinary teams design personalized care plans using advanced therapies.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Chemotherapy &amp; targeted therapy</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Immunotherapy</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Cancer surgery</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Palliative care &amp; pain management</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Cancer screening programs</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Post-treatment survivorship clinics</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Breast, lung, colorectal cancers</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Leukemia &amp; lymphomas</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Head &amp; neck cancers</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Gynecological cancers</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Skin cancers</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="oncologyFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#oncCollapse1" aria-expanded="true" aria-controls="oncCollapse1"> Do you offer second opinions? </button></h6>\r\n</div>\r\n<div id="oncCollapse1" class="collapse" aria-labelledby="faq1" data-parent="#oncologyFaqAccordion">\r\n<div class="card-body text-dark">Yes, in-person or via teleconsultation.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#oncCollapse2" aria-expanded="false" aria-controls="oncCollapse2"> Is palliative care available? </button></h6>\r\n</div>\r\n<div id="oncCollapse2" class="collapse" aria-labelledby="faq2" data-parent="#oncologyFaqAccordion">\r\n<div class="card-body text-dark">Yes, for symptom relief and quality of life improvement.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#oncCollapse3" aria-expanded="false" aria-controls="oncCollapse3"> Do you provide cancer screening? </button></h6>\r\n</div>\r\n<div id="oncCollapse3" class="collapse" aria-labelledby="faq3" data-parent="#oncologyFaqAccordion">\r\n<div class="card-body text-dark">Yes, for common cancers.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap 4.5 JS dependencies -->','\r',char(13)),'\n',char(10)),17,1,'fa-ribbon','bg-amber-50','text-amber-100','from-amber-500 to-orange-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 10:24:52','<ul><li>Chemotherapy & targeted therapy</li><li>Immunotherapy</li><li>Cancer surgery</li><li>Palliative care & pain management</li><li>Cancer screening programs</li><li>Post-treatment survivorship clinics</li></ul>','<ul><li>Breast, lung, colorectal cancers</li><li>Leukemia & lymphomas</li><li>Head & neck cancers</li><li>Gynecological cancers</li><li>Skin cancers</li></ul>','',NULL,NULL,'[{"question":"Do you offer second opinions?","answer":"Yes, in-person or via teleconsultation."},{"question":"Is palliative care available?","answer":"Yes, for symptom relief and quality of life improvement."},{"question":"Do you provide cancer screening?","answer":"Yes, for common cancers."}]');
INSERT INTO departments VALUES(3,'Cardiology','cardiology','Every heartbeat matters — and we’re here to protect it.','The Cardiology Department at AMZ Hospital Ltd. provides comprehensive heart care—from prevention and diagnosis to advanced treatment of cardiovascular diseases. Our skilled cardiologists manage conditions such as hypertension, coronary artery disease, heart failure, arrhythmias, and valvular disorders. Equipped with modern diagnostic tools, including echocardiography, ECG, and stress testing, along with interventional facilities, we deliver precise, timely, and life-saving care for heart health.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 220px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Cardiology</h2>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;The Cardiology Department at AMZ Hospital Ltd. provides comprehensive heart care&mdash;from prevention and diagnosis to advanced treatment of cardiovascular diseases. Our skilled cardiologists manage conditions such as hypertension, coronary artery disease, heart failure, arrhythmias, and valvular disorders. Equipped with modern diagnostic tools, including echocardiography, ECG, and stress testing, along with interventional facilities, we deliver precise, timely, and life-saving care for heart health.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Angiograms</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Bypass surgery</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Minimally invasive heart procedures</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Management of heart failure and rhythm abnormalities</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>ECG, echocardiography, treadmill testing</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Angiogram &amp; angioplasty (PTCA)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Bypass surgery (CABG) coordination</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Pacemaker implantation</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Heart failure management</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Preventive cardiology programs</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Coronary artery disease</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Hypertension</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Rheumatic heart disease</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Arrhythmias</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Myocardial infarction</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Heart failure</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Associated Health Packages Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Associated Health Packages</h5>\r\n<ul class="list-unstyled mb-0">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>General heart check-ups, lipid panels, and ECG bundles</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Heart Health Check-Up</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Post-Heart Attack Care Package</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Hypertension &amp; Cardiac Risk Program</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="cardioFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="cf1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#cardioCollapse1" aria-expanded="true" aria-controls="cardioCollapse1">How to book a cardiology appointment?</button></h6>\r\n</div>\r\n<div id="cardioCollapse1" class="collapse" aria-labelledby="cf1" data-parent="#cardioFaqAccordion">\r\n<div class="card-body text-dark">Appointments can be booked via our website, call center, or outpatient department.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="cf2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#cardioCollapse2" aria-expanded="false" aria-controls="cardioCollapse2">What investigations are typically done?</button></h6>\r\n</div>\r\n<div id="cardioCollapse2" class="collapse" aria-labelledby="cf2" data-parent="#cardioFaqAccordion">\r\n<div class="card-body text-dark">Common investigations include ECG, echocardiography, stress testing, and other diagnostic tests as advised by the cardiologist.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="cf3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#cardioCollapse3" aria-expanded="false" aria-controls="cardioCollapse3">Payment options?</button></h6>\r\n</div>\r\n<div id="cardioCollapse3" class="collapse" aria-labelledby="cf3" data-parent="#cardioFaqAccordion">\r\n<div class="card-body text-dark">AMZ Hospital accepts major insurance plans and online/offline payments.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="cf4" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#cardioCollapse4" aria-expanded="false" aria-controls="cardioCollapse4">Do you offer emergency heart attack care?</button></h6>\r\n</div>\r\n<div id="cardioCollapse4" class="collapse" aria-labelledby="cf4" data-parent="#cardioFaqAccordion">\r\n<div class="card-body text-dark">Yes, 24/7 with a dedicated cardiac team.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="cf5" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#cardioCollapse5" aria-expanded="false" aria-controls="cardioCollapse5">Can I book a preventive heart screening?</button></h6>\r\n</div>\r\n<div id="cardioCollapse5" class="collapse" aria-labelledby="cf5" data-parent="#cardioFaqAccordion">\r\n<div class="card-body text-dark">Yes, through our cardiac wellness program.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="cf6" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#cardioCollapse6" aria-expanded="false" aria-controls="cardioCollapse6">Do you perform bypass surgery here?</button></h6>\r\n</div>\r\n<div id="cardioCollapse6" class="collapse" aria-labelledby="cf6" data-parent="#cardioFaqAccordion">\r\n<div class="card-body text-dark">Surgeries are coordinated with partner cardiac surgical units.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap JS dependencies -->','\r',char(13)),'\n',char(10)),3,1,'fa-heart-pulse','bg-blue-50','text-blue-100','from-blue-600 to-indigo-700',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 05:35:50','<ul><li>Angiograms</li><li>Bypass surgery</li><li>Minimally invasive heart procedures</li><li>Management of heart failure and rhythm abnormalities</li><li>ECG, echocardiography, treadmill testing</li><li>Angiogram & angioplasty (PTCA)</li><li>Bypass surgery (CABG) coordination</li><li>Pacemaker implantation</li><li>Heart failure management</li><li>Preventive cardiology programs</li></ul>','<ul><li>Coronary artery disease</li><li>Hypertension</li><li>Rheumatic heart disease</li><li>Arrhythmias</li><li>Myocardial infarction</li><li>Heart failure</li></ul>','<ul><li>General heart check-ups, lipid panels, and ECG bundles</li><li>Heart Health Check-Up</li><li>Post-Heart Attack Care Package</li><li>Hypertension & Cardiac Risk Program</li></ul>',NULL,NULL,'[{"question":"How to book a cardiology appointment?","answer":"Appointments can be booked via our website, call center, or outpatient department."},{"question":"What investigations are typically done?","answer":"Common investigations include ECG, echocardiography, stress testing, and other diagnostic tests as advised by the cardiologist."},{"question":"Payment options?","answer":"AMZ Hospital accepts major insurance plans and online/offline payments."},{"question":"Do you offer emergency heart attack care?","answer":"Yes, 24/7 with a dedicated cardiac team."},{"question":"Can I book a preventive heart screening?","answer":"Yes, through our cardiac wellness program."},{"question":"Do you perform bypass surgery here?","answer":"Surgeries are coordinated with partner cardiac surgical units."}]');
INSERT INTO departments VALUES(4,'Cardiovascular Surgery','cardiovascular-surgery','NULL',NULL,replace(' <p class="pbmit-firstletter">\n        Main Hospitals or larger hospital systems may provide their own ambulance service as a service to the community, or where ambulance care is unreliable or chargeable. Many hospital-based EMS departments operate solely with their hospital\n     </p>\n     <p>The physicians will attempt to treat casualties at the scene and will only transport them to hospital if it is deemed necessary. If patients are transported to hospital, they are more likely to go straight to a ward rather than to <u>an emergency department</u> . Countries that use this model include Austria, France, Belgium, Luxembourg, Italy, Spain, Brazil and Chile.</p>\n     <div class="row">\n        <div class="col-md-6">\n           <ul class="list-group list-group-borderless">\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">That extremely painful or again is there anyone.</span>\n              </li>\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">Indignation and dislike men who are so beguiled</span>\n              </li>\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">Desires these cases are perfectly simple easy distinguish.</span>\n              </li>\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">That extremely painful or again that is there anyone.</span>\n              </li>\n           </ul>\n        </div>\n        <div class="col-md-6">\n           <ul class="list-group list-group-borderless">\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">Starchy foods are a key food group in healthy eating</span>\n              </li>\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">People are sleeping much less than they did in the past</span>\n              </li>\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">Don’t smoke or use drugs, and only drink in moderation</span>\n              </li>\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">Your body is full of trillions of bacteria, viruses and fungi</span>\n              </li>\n           </ul>\n        </div>\n     </div>','\n',char(10)),0,0,'fa-heart-circle-bolt','bg-red-50','text-red-100','from-red-500 to-pink-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 04:42:58',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO departments VALUES(5,'Colorectal Surgery','colorectal-surgery','Restoring comfort, dignity, and confidence through expert care','The Colorectal Surgery Department at AMZ Hospital Ltd. specializes in the surgical management of diseases affecting the colon, rectum, and anus. Our team treats conditions such as colorectal cancer, inflammatory bowel disease, hemorrhoids, fistulas, and diverticular disease using advanced techniques—including minimally invasive and laparoscopic surgery—for faster recovery and better outcomes. We are committed to delivering safe, effective, and compassionate surgical care tailored to each patient''s needs.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 220px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Colorectal Surgery</h2>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">The Colorectal Surgery Department at AMZ Hospital Ltd. specializes in the surgical management of diseases affecting the colon, rectum, and anus. Our team treats conditions such as colorectal cancer, inflammatory bowel disease, hemorrhoids, fistulas, and diverticular disease using advanced techniques&mdash;including minimally invasive and laparoscopic surgery&mdash;for faster recovery and better outcomes. We are committed to delivering safe, effective, and compassionate surgical care tailored to each patient&rsquo;s needs.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Hemorrhoidectomy</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Fistula &amp; fissure surgery</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Laparoscopic colorectal surgery</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Colon cancer surgery</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Stoma care &amp; reversal</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Anal sphincter repair</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Hemorrhoids</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Anal fissures &amp; fistulas</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Colorectal cancer</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Diverticulitis</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Inflammatory bowel disease</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Associated Health Packages Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Associated Health Packages</h5>\r\n<ul class="list-unstyled mb-0">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Colorectal Cancer Screening Package</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Hemorrhoid Treatment Package</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Post-Colorectal Surgery Recovery Plan</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="colorectalFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="cf1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#colorectalCollapse1" aria-expanded="true" aria-controls="colorectalCollapse1">Do you treat anal fissures without surgery?</button></h6>\r\n</div>\r\n<div id="colorectalCollapse1" class="collapse" aria-labelledby="cf1" data-parent="#colorectalFaqAccordion">\r\n<div class="card-body text-dark">Yes, with medication and lifestyle modification if detected early.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="cf2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#colorectalCollapse2" aria-expanded="false" aria-controls="colorectalCollapse2">Is colorectal cancer preventable?</button></h6>\r\n</div>\r\n<div id="colorectalCollapse2" class="collapse" aria-labelledby="cf2" data-parent="#colorectalFaqAccordion">\r\n<div class="card-body text-dark">Early detection through screening greatly reduces risk.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="cf3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#colorectalCollapse3" aria-expanded="false" aria-controls="colorectalCollapse3">How soon can I return to work after surgery?</button></h6>\r\n</div>\r\n<div id="colorectalCollapse3" class="collapse" aria-labelledby="cf3" data-parent="#colorectalFaqAccordion">\r\n<div class="card-body text-dark">Usually within 1&ndash;2 weeks for minor procedures, depending on your recovery and surgeon&rsquo;s advice.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap JS dependencies -->','\r',char(13)),'\n',char(10)),7,1,'fa-notes-medical','bg-purple-50','text-purple-100','from-purple-500 to-fuchsia-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 09:58:14','<ul><li>Hemorrhoidectomy</li><li>Fistula & fissure surgery</li><li>Laparoscopic colorectal surgery</li><li>Colon cancer surgery</li><li>Stoma care & reversal</li><li>Anal sphincter repair</li></ul>','<ul><li>Hemorrhoids</li><li>Anal fissures & fistulas</li><li>Colorectal cancer</li><li>Diverticulitis</li><li>Inflammatory bowel disease</li></ul>','<ul><li>Colorectal Cancer Screening Package</li><li>Hemorrhoid Treatment Package</li><li>Post-Colorectal Surgery Recovery Plan</li></ul>',NULL,NULL,'[{"question":"Do you treat anal fissures without surgery?","answer":"Yes, with medication and lifestyle modification if detected early."},{"question":"Is colorectal cancer preventable?","answer":"Early detection through screening greatly reduces risk."},{"question":"How soon can I return to work after surgery?","answer":"Usually within 1–2 weeks for minor procedures, depending on your recovery and surgeon''s advice."}]');
INSERT INTO departments VALUES(6,'Dermatology & Venereology','dermatology-&-venereology','“‘Because healthy skin is more than appearance — it’s confidence.’”','The Dermatology Department diagnoses and treats skin, hair, and nail disorders, offering both medical and cosmetic dermatology services.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Dermatology &amp; Venereology</h2>\r\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;</p>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #111;">The Dermatology Department diagnoses and treats skin, hair, and nail disorders, offering both medical and cosmetic dermatology services.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Acne &amp; eczema management</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Psoriasis treatment</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Skin cancer screening &amp; biopsy</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Cosmetic dermatology (peels, laser therapy)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Hair loss treatment programs</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Allergy patch testing</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Acne, rosacea</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Eczema, psoriasis</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Fungal infections</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Vitiligo, pigmentation disorders</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Alopecia</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="dermFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="dfaq1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#dermCollapse1" aria-expanded="true" aria-controls="dermCollapse1"> Do you offer laser treatments? </button></h6>\r\n</div>\r\n<div id="dermCollapse1" class="collapse" aria-labelledby="dfaq1" data-parent="#dermFaqAccordion">\r\n<div class="card-body text-dark">Yes, for hair removal, pigmentation, and scars.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="dfaq2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#dermCollapse2" aria-expanded="false" aria-controls="dermCollapse2"> Can you treat hair loss? </button></h6>\r\n</div>\r\n<div id="dermCollapse2" class="collapse" aria-labelledby="dfaq2" data-parent="#dermFaqAccordion">\r\n<div class="card-body text-dark">Yes, with medical and procedural options.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="dfaq3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#dermCollapse3" aria-expanded="false" aria-controls="dermCollapse3"> Are treatments safe during pregnancy? </button></h6>\r\n</div>\r\n<div id="dermCollapse3" class="collapse" aria-labelledby="dfaq3" data-parent="#dermFaqAccordion">\r\n<div class="card-body text-dark">Certain treatments are; your dermatologist will guide you.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap 4.5 JS dependencies -->','\r',char(13)),'\n',char(10)),21,1,'fa-hand-sparkles','bg-orange-50','text-orange-100','from-orange-500 to-amber-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 10:26:31','<ul><li>Acne & eczema management</li><li>Psoriasis treatment</li><li>Skin cancer screening & biopsy</li><li>Cosmetic dermatology (peels, laser therapy)</li><li>Hair loss treatment programs</li><li>Allergy patch testing</li></ul>','<ul><li>Acne, rosacea</li><li>Eczema, psoriasis</li><li>Fungal infections</li><li>Vitiligo, pigmentation disorders</li><li>Alopecia</li></ul>','',NULL,NULL,'[{"question":"Do you offer laser treatments?","answer":"Yes, for hair removal, pigmentation, and scars."},{"question":"Can you treat hair loss?","answer":"Yes, with medical and procedural options."},{"question":"Are treatments safe during pregnancy?","answer":"Certain treatments are; your dermatologist will guide you."}]');
INSERT INTO departments VALUES(7,'ENT','ent','Clear hearing, easy breathing, healthy living.','The ENT Department specializes in diagnosing and treating disorders of the ear, nose, and throat—including surgical interventions and outpatient care.',replace(replace('<div class="container">\r\n<div class="row"><!-- Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100 w-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e0f2f1); color: #111; backdrop-filter: blur(8px);">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">ENT (Ear, Nose &amp; Throat)</h2>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;"><br><br>The ENT Department specializes in diagnosing and treating disorders of the ear, nose, and throat&mdash;including surgical interventions and outpatient care.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Key Services -->\r\n<div class="col-md-6 col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100 w-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px);">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Hearing tests &amp; hearing aid fitting</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Endoscopic sinus surgery</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Tonsillectomy &amp; adenoidectomy</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Ear drum repair (tympanoplasty)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Vertigo assessment</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Voice disorder management</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Common Conditions -->\r\n<div class="col-md-6 col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100 w-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px);">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Sinusitis, chronic ear infections, hearing loss</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Nasal obstruction, throat disorders, head-neck tumors</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Health Packages -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100 w-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px);">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Associated Health Packages</h5>\r\n<ul class="list-unstyled mb-0">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Hearing Screening Package</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Sinus Health Package</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Allergy &amp; ENT Care Program</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQs -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100 w-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px);">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="entFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="efq1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#entCollapse1" aria-expanded="true" aria-controls="entCollapse1"> How to schedule ear or sinus surgery? </button></h6>\r\n</div>\r\n<div id="entCollapse1" class="collapse" aria-labelledby="efq1" data-parent="#entFaqAccordion">\r\n<div class="card-body text-dark">You can book through our outpatient desk or via online appointment booking. Pre-surgical evaluation is required.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="efq2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#entCollapse2" aria-expanded="false" aria-controls="entCollapse2"> What tests are included in ENT evaluation? </button></h6>\r\n</div>\r\n<div id="entCollapse2" class="collapse" aria-labelledby="efq2" data-parent="#entFaqAccordion">\r\n<div class="card-body text-dark">ENT evaluation may include hearing tests, nasal endoscopy, throat examination, and allergy testing as needed.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="efq3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#entCollapse3" aria-expanded="false" aria-controls="entCollapse3"> Are hearing tests and audiometry available? </button></h6>\r\n</div>\r\n<div id="entCollapse3" class="collapse" aria-labelledby="efq3" data-parent="#entFaqAccordion">\r\n<div class="card-body text-dark">Yes, we have a dedicated audiology unit equipped for hearing tests and full audiometry assessments.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>','\r',char(13)),'\n',char(10)),12,1,'fa-ear-listen','bg-cyan-50','text-cyan-100','from-cyan-500 to-sky-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 09:58:36','<ul><li>Hearing tests & hearing aid fitting</li><li>Endoscopic sinus surgery</li><li>Tonsillectomy & adenoidectomy</li><li>Ear drum repair (tympanoplasty)</li><li>Vertigo assessment</li><li>Voice disorder management</li></ul>','<ul><li>Sinusitis, chronic ear infections, hearing loss</li><li>Nasal obstruction, throat disorders, head-neck tumors</li></ul>','<ul><li>Hearing Screening Package</li><li>Sinus Health Package</li><li>Allergy & ENT Care Program</li></ul>',NULL,NULL,'[{"question":"How to schedule ear or sinus surgery?","answer":"You can book through our outpatient desk or via online appointment booking. Pre-surgical evaluation is required."},{"question":"What tests are included in ENT evaluation?","answer":"ENT evaluation may include hearing tests, nasal endoscopy, throat examination, and allergy testing as needed."},{"question":"Are hearing tests and audiometry available?","answer":"Yes, we have a dedicated audiology unit equipped for hearing tests and full audiometry assessments."}]');
INSERT INTO departments VALUES(8,'Hepatology & Gastroenterology','hepatology-&-gastroenterology','Healthy digestion, healthier life.',NULL,replace('<div class="container">\n<div class="row"><!-- Intro Card -->\n<div class="col-md-6 mb-4 d-flex" style="max-width: 500px;">\n<div class="card shadow-sm text-white h-100" style="border-radius: 12px; background: linear-gradient(135deg, #0f2027, #203a43, #2c5364); width: 100%; height: 350px;">\n<div class="card-body d-flex flex-column">\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #b2ebf2;">Hepatology &amp; Gastroenterology</h2>\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #e0f7fa;">&nbsp;</p>\n<p style="font-family: ''Calibri'', sans-serif;">The Hepatology &amp; Gastroenterology Department at AMZ Hospital provides advanced diagnostic, therapeutic, and preventive care for liver, gallbladder, pancreas, and digestive tract disorders. Our specialists combine state-of-the-art technology with evidence-based medicine to manage complex gastrointestinal and hepatic conditions, from common digestive complaints to advanced liver disease.</p>\n</div>\n</div>\n</div>\n<!-- Key Services Card -->\n<div class="col-md-6 mb-4 d-flex" style="max-width: 500px;">\n<div class="card shadow-sm text-white h-100" style="border-radius: 12px; background: linear-gradient(135deg, #1c1c2b, #2c3e50, #3a6073); width: 100%; height: 350px;">\n<div class="card-body d-flex flex-column">\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #b2ebf2;">Key Services &amp; Procedures</h5>\n<ul class="list-unstyled mb-0 flex-grow-1">\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Diagnostic endoscopy (Upper GI endoscopy, Colonoscopy, ERCP)</li>\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Liver disease management (Hepatitis B &amp; C, fatty liver, cirrhosis)</li>\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Pancreatic disorder management</li>\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Gallbladder and biliary disease treatment</li>\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Capsule endoscopy</li>\n<li class="mb-2"><span class="text-success mr-2">✓ </span>GI cancer screening and surveillance</li>\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Nutritional and lifestyle counseling for digestive health</li>\n</ul>\n</div>\n</div>\n</div>\n<!-- Common Conditions Card -->\n<div class="col-md-6 mb-4 d-flex" style="max-width: 500px;">\n<div class="card shadow-sm text-white h-100" style="border-radius: 12px; background: linear-gradient(135deg, #0f2027, #203a43, #2c5364); width: 100%; height: 350px;">\n<div class="card-body d-flex flex-column">\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #b2ebf2;">Common Conditions Treated</h5>\n<ul class="list-unstyled mb-0 flex-grow-1">\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Acid reflux (GERD), gastritis, peptic ulcers</li>\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Hepatitis B, Hepatitis C, alcoholic and non-alcoholic fatty liver disease</li>\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Irritable bowel syndrome (IBS), inflammatory bowel disease (IBD)</li>\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Gallstones and biliary tract obstruction</li>\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Pancreatitis</li>\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Liver cirrhosis and complications</li>\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Gastrointestinal bleeding</li>\n</ul>\n</div>\n</div>\n</div>\n<!-- Health Packages Card -->\n<div class="col-md-6 mb-4 d-flex" style="max-width: 500px;">\n<div class="card shadow-sm text-white h-100" style="border-radius: 12px; background: linear-gradient(135deg, #1c1c2b, #2c3e50, #3a6073); width: 100%; height: 350px;">\n<div class="card-body d-flex flex-column">\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #b2ebf2;">Associated Health Packages</h5>\n<ul class="list-unstyled mb-0 flex-grow-1">\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Liver Health Screening Package</li>\n<li class="mb-2"><span class="text-success mr-2">✓ </span>GI Cancer Screening Package</li>\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Digestive Wellness Package</li>\n</ul>\n</div>\n</div>\n</div>\n<!-- FAQs Card (full width) -->\n<div class="col-12 mb-4 d-flex">\n<div class="card shadow-sm text-white h-100" style="border-radius: 12px; background: linear-gradient(135deg, #0f2027, #203a43, #2c5364); width: 100%; height: 350px;">\n<div class="card-body">\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #b2ebf2;">FAQs</h5>\n<div id="hepatologyFaqAccordion">\n<div class="card mb-2 bg-dark text-white">\n<div id="faq1" class="card-header p-2">\n<h6 class="mb-0"><button class="btn btn-link text-white" data-toggle="collapse" data-target="#collapse1" aria-expanded="true" aria-controls="collapse1"> What symptoms indicate I should visit a gastroenterologist? </button></h6>\n</div>\n<div id="collapse1" class="collapse" aria-labelledby="faq1" data-parent="#hepatologyFaqAccordion">\n<div class="card-body text-white">Persistent digestive discomfort, jaundice, unexplained weight loss, or abnormal lab tests.</div>\n</div>\n</div>\n<div class="card mb-2 bg-dark text-white">\n<div id="faq2" class="card-header p-2">\n<h6 class="mb-0"><button class="btn btn-link text-white" data-toggle="collapse" data-target="#collapse2" aria-expanded="false" aria-controls="collapse2"> How do I prepare for an endoscopy or colonoscopy? </button></h6>\n</div>\n<div id="collapse2" class="collapse" aria-labelledby="faq2" data-parent="#hepatologyFaqAccordion">\n<div class="card-body text-white">Follow fasting instructions and bowel preparation guidelines provided by the department.</div>\n</div>\n</div>\n<div class="card mb-2 bg-dark text-white">\n<div id="faq3" class="card-header p-2">\n<h6 class="mb-0"><button class="btn btn-link text-white" data-toggle="collapse" data-target="#collapse3" aria-expanded="false" aria-controls="collapse3"> Are hepatitis treatments available at AMZ Hospital? </button></h6>\n</div>\n<div id="collapse3" class="collapse" aria-labelledby="faq3" data-parent="#hepatologyFaqAccordion">\n<div class="card-body text-white">Yes, including antiviral therapy and liver disease management programs.</div>\n</div>\n</div>\n<div class="card mb-2 bg-dark text-white">\n<div id="faq4" class="card-header p-2">\n<h6 class="mb-0"><button class="btn btn-link text-white" data-toggle="collapse" data-target="#collapse4" aria-expanded="false" aria-controls="collapse4"> Does the department offer same-day diagnostic tests? </button></h6>\n</div>\n<div id="collapse4" class="collapse" aria-labelledby="faq4" data-parent="#hepatologyFaqAccordion">\n<div class="card-body text-white">Yes, select diagnostic procedures are available on the same day.</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<!-- Bootstrap 4.5 JS dependencies -->','\n',char(10)),0,0,'fa-liver','bg-lime-50','text-lime-100','from-green-500 to-lime-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 04:42:58',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO departments VALUES(9,'General, Laparoscopic & Laser Surgery','general,-laparoscopic-&-laser-surgery','Precision surgery with minimal scars and maximum care','The General, Laparoscopic & Laser Surgery Department at AMZ Hospital Ltd. provides surgical solutions for a wide range of conditions, from routine procedures to complex operations. Our surgeons are skilled in minimally invasive and laser techniques, ensuring reduced pain, minimal scarring, and faster recovery. We manage cases including hernias, gallstones, appendicitis, varicose veins, and other surgical conditions with precision and care.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 220px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">General, Laparoscopic &amp; Laser Surgery</h2>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">The General, Laparoscopic &amp; Laser Surgery Department at AMZ Hospital Ltd. provides surgical solutions for a wide range of conditions, from routine procedures to complex operations. Our surgeons are skilled in minimally invasive and laser techniques, ensuring reduced pain, minimal scarring, and faster recovery. We manage cases including hernias, gallstones, appendicitis, varicose veins, and other surgical conditions with precision and care.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>General surgical procedures (hernia repair, appendectomy, gallbladder surgery)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Advanced laparoscopic (keyhole) surgeries</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Laser-assisted surgeries (piles, fistula, varicose veins)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Minor surgical interventions under local anesthesia</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Pre- and post-operative care and counseling</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Gallstones and gallbladder diseases</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Appendicitis</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Hernia (inguinal, umbilical, incisional)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Hemorrhoids, anal fissures, fistula-in-ano</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Varicose veins</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Skin and soft tissue lumps or cysts</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Associated Health Packages Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Associated Health Packages</h5>\r\n<ul class="list-unstyled mb-0">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Laser Hemorrhoidectomy Package</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Keyhole Gallbladder Surgery Package</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="surgeryFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="sf1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#surgeryCollapse1" aria-expanded="true" aria-controls="surgeryCollapse1">What is the difference between laparoscopic and open surgery?</button></h6>\r\n</div>\r\n<div id="surgeryCollapse1" class="collapse" aria-labelledby="sf1" data-parent="#surgeryFaqAccordion">\r\n<div class="card-body text-dark">Laparoscopic surgery is minimally invasive with small incisions and faster recovery, whereas open surgery involves larger incisions.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="sf2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#surgeryCollapse2" aria-expanded="false" aria-controls="surgeryCollapse2">How soon can I return to work after laser surgery?</button></h6>\r\n</div>\r\n<div id="surgeryCollapse2" class="collapse" aria-labelledby="sf2" data-parent="#surgeryFaqAccordion">\r\n<div class="card-body text-dark">Recovery is usually quicker than conventional surgery; many patients return to work within 1&ndash;2 weeks, depending on procedure and healing.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="sf3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#surgeryCollapse3" aria-expanded="false" aria-controls="surgeryCollapse3">Are laser surgeries covered by insurance?</button></h6>\r\n</div>\r\n<div id="surgeryCollapse3" class="collapse" aria-labelledby="sf3" data-parent="#surgeryFaqAccordion">\r\n<div class="card-body text-dark">Most major insurance plans cover laser surgeries; coverage depends on your policy and procedure type.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="sf4" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#surgeryCollapse4" aria-expanded="false" aria-controls="surgeryCollapse4">How do I prepare for laparoscopic surgery?</button></h6>\r\n</div>\r\n<div id="surgeryCollapse4" class="collapse" aria-labelledby="sf4" data-parent="#surgeryFaqAccordion">\r\n<div class="card-body text-dark">Pre-surgery preparation includes fasting, necessary lab tests, imaging, and following your surgeon''s instructions carefully.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap JS dependencies -->','\r',char(13)),'\n',char(10)),6,1,'fa-procedures','bg-indigo-50','text-indigo-100','from-indigo-500 to-blue-700',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 05:41:33','<ul><li>General surgical procedures (hernia repair, appendectomy, gallbladder surgery)</li><li>Advanced laparoscopic (keyhole) surgeries</li><li>Laser-assisted surgeries (piles, fistula, varicose veins)</li><li>Minor surgical interventions under local anesthesia</li><li>Pre- and post-operative care and counseling</li></ul>','<ul><li>Gallstones and gallbladder diseases</li><li>Appendicitis</li><li>Hernia (inguinal, umbilical, incisional)</li><li>Hemorrhoids, anal fissures, fistula-in-ano</li><li>Varicose veins</li><li>Skin and soft tissue lumps or cysts</li></ul>','<ul><li>Laser Hemorrhoidectomy Package</li><li>Keyhole Gallbladder Surgery Package</li></ul>',NULL,NULL,'[{"question":"What is the difference between laparoscopic and open surgery?","answer":"Laparoscopic surgery is minimally invasive with small incisions and faster recovery, whereas open surgery involves larger incisions."},{"question":"How soon can I return to work after laser surgery?","answer":"Recovery is usually quicker than conventional surgery; many patients return to work within 1–2 weeks, depending on procedure and healing."},{"question":"Are laser surgeries covered by insurance?","answer":"Most major insurance plans cover laser surgeries; coverage depends on your policy and procedure type."},{"question":"How do I prepare for laparoscopic surgery?","answer":"Pre-surgery preparation includes fasting, necessary lab tests, imaging, and following your surgeon''s instructions carefully."}]');
INSERT INTO departments VALUES(10,'Gynecology & Obstetrics','gynecology-&-obstetrics','Your partner in health and safe motherhood.','The Gynecology & Obstetrics Department at AMZ Hospital Ltd. is dedicated to delivering comprehensive, compassionate, and evidence-based care for women at every stage of life—from adolescence through menopause and beyond. Our highly skilled team of obstetricians, gynecologists and specialized nurses offers a full spectrum of services, including routine and high-risk pregnancy management, advanced gynecological surgery, infertility evaluation, menstrual disorder treatment, and preventive women''s health screenings. With state-of-the-art facilities, modern diagnostic support, and a patient-centered approach, we ensure safety, dignity, and personalized attention for every woman we serve.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 220px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Gynae &amp; Obs.</h2>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">The Gynecology &amp; Obstetrics Department at AMZ Hospital Ltd. is dedicated to delivering comprehensive, compassionate, and evidence-based care for women at every stage of life&mdash;from adolescence through menopause and beyond. Our highly skilled team of obstetricians, gynecologists and specialized nurses offers a full spectrum of services, including routine and high-risk pregnancy management, advanced gynecological surgery, infertility evaluation, menstrual disorder treatment, and preventive women&rsquo;s health screenings. With state-of-the-art facilities, modern diagnostic support, and a patient-centered approach, we ensure safety, dignity, and personalized attention for every woman we serve.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Antenatal &amp; postnatal care</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Normal &amp; cesarean deliveries</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Family planning services</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Menopause management</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Gynecological surgery (laparoscopy, hysterectomy)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Infertility evaluation</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>High-risk pregnancies</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Menstrual disorders</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>PCOS</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Fibroids</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Gynecological cancers</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Associated Health Packages Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Associated Health Packages</h5>\r\n<ul class="list-unstyled mb-0">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Pregnancy Care Package</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Well Woman Health Screening</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Menopause Wellness Package</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="gynaeFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="gf1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#gynCollapse1" aria-expanded="true" aria-controls="gynCollapse1">Do you have a NICU?</button></h6>\r\n</div>\r\n<div id="gynCollapse1" class="collapse" aria-labelledby="gf1" data-parent="#gynaeFaqAccordion">\r\n<div class="card-body text-dark">Yes, for newborn care.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="gf2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#gynCollapse2" aria-expanded="false" aria-controls="gynCollapse2">Is painless delivery available?</button></h6>\r\n</div>\r\n<div id="gynCollapse2" class="collapse" aria-labelledby="gf2" data-parent="#gynaeFaqAccordion">\r\n<div class="card-body text-dark">Yes, epidural anesthesia is offered.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="gf3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#gynCollapse3" aria-expanded="false" aria-controls="gynCollapse3">Do you offer family planning counseling?</button></h6>\r\n</div>\r\n<div id="gynCollapse3" class="collapse" aria-labelledby="gf3" data-parent="#gynaeFaqAccordion">\r\n<div class="card-body text-dark">Yes, with multiple safe options.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap JS dependencies -->','\r',char(13)),'\n',char(10)),2,1,'fa-person-pregnant','bg-pink-50','text-pink-100','from-pink-500 to-rose-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 05:39:39','<ul><li>Antenatal & postnatal care</li><li>Normal & cesarean deliveries</li><li>Family planning services</li><li>Menopause management</li><li>Gynecological surgery (laparoscopy, hysterectomy)</li><li>Infertility evaluation</li></ul>','<ul><li>High-risk pregnancies</li><li>Menstrual disorders</li><li>PCOS</li><li>Fibroids</li><li>Gynecological cancers</li></ul>','<ul><li>Pregnancy Care Package</li><li>Well Woman Health Screening</li><li>Menopause Wellness Package</li></ul>',NULL,NULL,'[{"question":"Do you have a NICU?","answer":"Yes, for newborn care."},{"question":"Is painless delivery available?","answer":"Yes, epidural anesthesia is offered."},{"question":"Do you offer family planning counseling?","answer":"Yes, with multiple safe options."}]');
INSERT INTO departments VALUES(11,'Haematology','haematology','‘Every drop of blood tells a story — we ensure it’s a healthy one.’','The Hematology Department at AMZ Hospital provides comprehensive diagnosis, treatment, and long-term management of blood disorders in both adults and children. Our expertise covers anemia, bleeding and clotting disorders, hematologic malignancies, and bone marrow diseases. The department works closely with Oncology, Pathology, and Transfusion Medicine for a multidisciplinary approach.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Hematology</h2>\r\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;</p>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #111;">The Hematology Department at AMZ Hospital provides comprehensive diagnosis, treatment, and long-term management of blood disorders in both adults and children. Our expertise covers anemia, bleeding and clotting disorders, hematologic malignancies, and bone marrow diseases. The department works closely with Oncology, Pathology, and Transfusion Medicine for a multidisciplinary approach.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Complete blood evaluation and diagnostic testing</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Bone marrow aspiration and biopsy</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Blood transfusion services with strict safety protocols</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Management of anemia (iron deficiency, vitamin-related, chronic disease)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Treatment of bleeding disorders (hemophilia, platelet disorders)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Clotting disorder evaluation and anticoagulation management</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Follow-up and monitoring of blood cancers (leukemia, lymphoma, myeloma)</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Iron deficiency anemia &amp; other anemias</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Hemophilia &amp; other clotting disorders</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Thrombocytopenia (low platelet count)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Leukemia, lymphoma, and multiple myeloma</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Deep vein thrombosis (DVT) &amp; other thromboembolic conditions</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Bone marrow disorders (aplastic anemia, myelodysplastic syndromes)</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="hemaFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="hf1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#hemaCollapse1" aria-expanded="true" aria-controls="hemaCollapse1"> Do I need a referral to see a hematologist? </button></h6>\r\n</div>\r\n<div id="hemaCollapse1" class="collapse" aria-labelledby="hf1" data-parent="#hemaFaqAccordion">\r\n<div class="card-body text-dark">Referral is not mandatory, but bringing previous reports helps for proper evaluation.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="hf2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#hemaCollapse2" aria-expanded="false" aria-controls="hemaCollapse2"> Are blood transfusions done in the hospital? </button></h6>\r\n</div>\r\n<div id="hemaCollapse2" class="collapse" aria-labelledby="hf2" data-parent="#hemaFaqAccordion">\r\n<div class="card-body text-dark">Yes, all transfusions are performed under strict safety protocols within the hospital.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="hf3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#hemaCollapse3" aria-expanded="false" aria-controls="hemaCollapse3"> Does the department manage blood cancers? </button></h6>\r\n</div>\r\n<div id="hemaCollapse3" class="collapse" aria-labelledby="hf3" data-parent="#hemaFaqAccordion">\r\n<div class="card-body text-dark">Yes, the department handles leukemia, lymphoma, myeloma, and related conditions in coordination with Oncology.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap 4.5 JS dependencies -->','\r',char(13)),'\n',char(10)),22,1,'fa-droplet','bg-rose-50','text-rose-100','from-red-500 to-rose-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 10:21:14','<ul><li>Complete blood evaluation and diagnostic testing</li><li>Bone marrow aspiration and biopsy</li><li>Blood transfusion services with strict safety protocols</li><li>Management of anemia (iron deficiency, vitamin-related, chronic disease)</li><li>Treatment of bleeding disorders (hemophilia, platelet disorders)</li><li>Clotting disorder evaluation and anticoagulation management</li><li>Follow-up and monitoring of blood cancers (leukemia, lymphoma, myeloma)</li></ul>','<ul><li>Iron deficiency anemia & other anemias</li><li>Hemophilia & other clotting disorders</li><li>Thrombocytopenia (low platelet count)</li><li>Leukemia, lymphoma, and multiple myeloma</li><li>Deep vein thrombosis (DVT) & other thromboembolic conditions</li><li>Bone marrow disorders (aplastic anemia, myelodysplastic syndromes)</li></ul>','',NULL,NULL,'[{"question":"Do I need a referral to see a hematologist?","answer":"Referral is not mandatory, but bringing previous reports helps for proper evaluation."},{"question":"Are blood transfusions done in the hospital?","answer":"Yes, all transfusions are performed under strict safety protocols within the hospital."},{"question":"Does the department manage blood cancers?","answer":"Yes, the department handles leukemia, lymphoma, myeloma, and related conditions in coordination with Oncology."}]');
INSERT INTO departments VALUES(12,'Hepatobiliary & Pancreatic Surgery','hepatobiliary-&-pancreatic-surgery','Healthy digestion, healthier life.','The Hepatobiliary & Pancreatic Surgery Department at AMZ Hospital provides advanced, comprehensive surgical care for complex diseases of the liver, gallbladder, bile ducts, and pancreas. Our expert surgeons work closely with specialists in gastroenterology, oncology, radiology, and critical care to ensure precise diagnosis, optimal surgical planning, and seamless post-operative management.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 220px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Hepatobiliary &amp; Pancreatic Surgery</h2>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">The Hepatobiliary &amp; Pancreatic Surgery Department at AMZ Hospital provides advanced, comprehensive surgical care for complex diseases of the liver, gallbladder, bile ducts, and pancreas. Our expert surgeons work closely with specialists in gastroenterology, oncology, radiology, and critical care to ensure precise diagnosis, optimal surgical planning, and seamless post-operative management.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Hepatectomy (partial or full), liver tumor resection, and cyst removal</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Bile duct reconstruction, choledochal cyst excision, bile duct injury repair</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Laparoscopic and open cholecystectomy for gallstones or gallbladder disease</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Whipple procedure, distal pancreatectomy, enucleation of tumors</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Minimally Invasive &amp; Laparoscopic Procedures &ndash; Faster recovery, smaller scars</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Surgery for liver, bile duct, and pancreatic cancers</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Liver and pancreatic injury repair, diagnostic and therapeutic endoscopy</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Liver function assessment and treatment</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Hepatitis screening and management</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Treatment of acid reflux, ulcers, and digestive disorders</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Hepatocellular carcinoma, liver metastases, liver abscess, benign liver tumors</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Gallstones, bile duct stones, bile duct cancer, biliary strictures</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Pancreatic cancer, chronic pancreatitis, pancreatic cysts, insulinomas</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Trauma-related injuries to liver, bile ducts, or pancreas</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Complications from previous abdominal surgeries affecting the hepatobiliary system</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Associated Health Packages Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Associated Health Packages</h5>\r\n<ul class="list-unstyled mb-0">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Liver Health Screening Package</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>GI Cancer Screening Package</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Digestive Wellness Package</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="hepatoFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="hf1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#hepatoCollapse1" aria-expanded="true" aria-controls="hepatoCollapse1">How long is the typical hospital stay after surgery?</button></h6>\r\n</div>\r\n<div id="hepatoCollapse1" class="collapse" aria-labelledby="hf1" data-parent="#hepatoFaqAccordion">\r\n<div class="card-body text-dark">Hospital stay depends on the type and complexity of surgery, typically ranging from 5&ndash;14 days with proper post-operative care.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="hf2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#hepatoCollapse2" aria-expanded="false" aria-controls="hepatoCollapse2">Can liver or pancreatic cancer be cured with surgery?</button></h6>\r\n</div>\r\n<div id="hepatoCollapse2" class="collapse" aria-labelledby="hf2" data-parent="#hepatoFaqAccordion">\r\n<div class="card-body text-dark">Surgery can be curative for selected patients, often combined with chemotherapy or targeted therapy for optimal outcomes.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="hf3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#hepatoCollapse3" aria-expanded="false" aria-controls="hepatoCollapse3">Are pre-surgery lifestyle changes important?</button></h6>\r\n</div>\r\n<div id="hepatoCollapse3" class="collapse" aria-labelledby="hf3" data-parent="#hepatoFaqAccordion">\r\n<div class="card-body text-dark">Yes, proper nutrition, quitting smoking, and managing co-morbidities improve surgical outcomes and recovery.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap JS dependencies -->','\r',char(13)),'\n',char(10)),4,1,'fa-microscope','bg-red-50','text-red-100','from-red-500 to-orange-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 05:40:17','<ul><li>Hepatectomy (partial or full), liver tumor resection, and cyst removal</li><li>Bile duct reconstruction, choledochal cyst excision, bile duct injury repair</li><li>Laparoscopic and open cholecystectomy for gallstones or gallbladder disease</li><li>Whipple procedure, distal pancreatectomy, enucleation of tumors</li><li>Minimally Invasive & Laparoscopic Procedures – Faster recovery, smaller scars</li><li>Surgery for liver, bile duct, and pancreatic cancers</li><li>Liver and pancreatic injury repair, diagnostic and therapeutic endoscopy</li><li>Liver function assessment and treatment</li><li>Hepatitis screening and management</li><li>Treatment of acid reflux, ulcers, and digestive disorders</li></ul>','<ul><li>Hepatocellular carcinoma, liver metastases, liver abscess, benign liver tumors</li><li>Gallstones, bile duct stones, bile duct cancer, biliary strictures</li><li>Pancreatic cancer, chronic pancreatitis, pancreatic cysts, insulinomas</li><li>Trauma-related injuries to liver, bile ducts, or pancreas</li><li>Complications from previous abdominal surgeries affecting the hepatobiliary system</li></ul>','<ul><li>Liver Health Screening Package</li><li>GI Cancer Screening Package</li><li>Digestive Wellness Package</li></ul>',NULL,NULL,'[{"question":"How long is the typical hospital stay after surgery?","answer":"Hospital stay depends on the type and complexity of surgery, typically ranging from 5–14 days with proper post-operative care."},{"question":"Can liver or pancreatic cancer be cured with surgery?","answer":"Surgery can be curative for selected patients, often combined with chemotherapy or targeted therapy for optimal outcomes."},{"question":"Are pre-surgery lifestyle changes important?","answer":"Yes, proper nutrition, quitting smoking, and managing co-morbidities improve surgical outcomes and recovery."}]');
INSERT INTO departments VALUES(13,'Interventional Pain Medicine','interventional-pain-medicine','Because life is better when pain is under control.','The Pain Medicine Department at AMZ Hospital Ltd. focuses on diagnosing and treating chronic pain conditions through advanced, minimally invasive procedures. Our team addresses back pain, neck pain, joint pain, neuropathic pain, and cancer-related pain using evidence-based techniques, including nerve blocks, epidural injections, and radiofrequency ablation. Our goal is to restore mobility, reduce dependence on medication, and improve quality of life.',replace(replace('<div class="container"><!-- First Row: Interventional Pain Medicine Alone -->\r\n<div class="row justify-content-center">\r\n<div class="col-md-12 mb-4 d-flex" style="max-width: 1000px;">\r\n<div class="card shadow-sm text-white h-100" style="border-radius: 12px; background: linear-gradient(135deg, #0f2027, #2c5364, #00c6ff); width: 100%; height: 350px;">\r\n<div class="card-body d-flex flex-column">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #a3ffb0;">Interventional Pain Medicine</h2>\r\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #e0f7fa;">&nbsp;</p>\r\n<p style="font-family: ''Calibri'', sans-serif;">The Pain Medicine Department at AMZ Hospital Ltd. focuses on diagnosing and treating chronic pain conditions through advanced, minimally invasive procedures. Our team addresses back pain, neck pain, joint pain, neuropathic pain, and cancer-related pain using evidence-based techniques, including nerve blocks, epidural injections, and radiofrequency ablation. Our goal is to restore mobility, reduce dependence on medication, and improve quality of life.</p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Second Row: Key Services & Common Conditions -->\r\n<div class="row justify-content-center"><!-- Key Services -->\r\n<div class="col-md-6 mb-4 d-flex" style="max-width: 500px;">\r\n<div class="card shadow-sm text-white h-100" style="border-radius: 12px; background: linear-gradient(135deg, #000000, #00695c, #00acc1); width: 100%; height: 350px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #b2ff59;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Interventional pain management (nerve blocks, injections)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Chronic back and neck pain treatment</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Headache and migraine management</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Cancer pain control</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Physiotherapy and rehabilitation integration</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex" style="max-width: 500px;">\r\n<div class="card shadow-sm text-white h-100" style="border-radius: 12px; background: linear-gradient(135deg, #000000, #004d40, #00838f); width: 100%; height: 350px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #80deea;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Sciatica and nerve compression</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Osteoarthritis and joint pain</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Fibromyalgia</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Post-surgical pain</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Neuropathic pain</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Third Row: FAQs -->\r\n<div class="row justify-content-center">\r\n<div class="col-md-12 mb-4 d-flex" style="max-width: 1000px;">\r\n<div class="card shadow-sm text-white h-100" style="border-radius: 12px; background: linear-gradient(135deg, #000000, #006064, #26c6da); width: 100%; height: 350px;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #b2ebf2;">FAQs</h5>\r\n<div id="painFaqAccordion">\r\n<div class="card mb-2 bg-dark text-white">\r\n<div id="pfaq1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-white" data-toggle="collapse" data-target="#pcollapse1" aria-expanded="true">Are nerve blocks safe?</button></h6>\r\n</div>\r\n<div id="pcollapse1" class="collapse" data-parent="#painFaqAccordion">\r\n<div class="card-body text-white">Yes, when performed by trained specialists, nerve blocks are generally safe with minimal risks.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-dark text-white">\r\n<div id="pfaq2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-white" data-toggle="collapse" data-target="#pcollapse2">How soon will pain relief be noticeable?</button></h6>\r\n</div>\r\n<div id="pcollapse2" class="collapse" data-parent="#painFaqAccordion">\r\n<div class="card-body text-white">Some patients feel relief within hours, while others may notice improvement over several days.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-dark text-white">\r\n<div id="pfaq3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-white" data-toggle="collapse" data-target="#pcollapse3">Do you offer non-drug pain management options?</button></h6>\r\n</div>\r\n<div id="pcollapse3" class="collapse" data-parent="#painFaqAccordion">\r\n<div class="card-body text-white">Yes, including physiotherapy, lifestyle modifications, and interventional therapies.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>','\r',char(13)),'\n',char(10)),28,1,'fa-hand-holding-medical','bg-violet-50','text-violet-100','from-violet-500 to-purple-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 10:24:07','<ul><li>Interventional pain management (nerve blocks, injections)</li><li>Chronic back and neck pain treatment</li><li>Headache and migraine management</li><li>Cancer pain control</li><li>Physiotherapy and rehabilitation integration</li></ul>','<ul><li>Sciatica and nerve compression</li><li>Osteoarthritis and joint pain</li><li>Fibromyalgia</li><li>Post-surgical pain</li><li>Neuropathic pain</li></ul>','',NULL,NULL,'[{"question":"Are nerve blocks safe?","answer":"Yes, when performed by trained specialists, nerve blocks are generally safe with minimal risks."},{"question":"How soon will pain relief be noticeable?","answer":"Some patients feel relief within hours, while others may notice improvement over several days."},{"question":"Do you offer non-drug pain management options?","answer":"Yes, including physiotherapy, lifestyle modifications, and interventional therapies."}]');
INSERT INTO departments VALUES(14,'Nephrology','nephrology','‘Caring for the body’s natural filter — your kidneys.’','The Nephrology Department manages kidney-related conditions, offering both medical and dialysis services for acute and chronic kidney disease.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f4f7f9, #e8f1f0, #dfe6f0); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Nephrology</h2>\r\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;</p>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #111;">The Nephrology Department manages kidney-related conditions, offering both medical and dialysis services for acute and chronic kidney disease.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Hemodialysis &amp; peritoneal dialysis</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Kidney biopsy</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Hypertension &amp; electrolyte disorder management</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Chronic kidney disease clinics</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Post-transplant follow-up</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Acute kidney injury</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Chronic kidney disease</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Kidney infections</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Nephrotic syndrome</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Polycystic kidney disease</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Health Packages & FAQs -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 200px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Associated Health Packages</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Kidney Function Screening Package</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Dialysis Care Program</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Hypertension &amp; Kidney Risk Program</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 200px;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">FAQs</h5>\r\n<div id="nephrologyFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#nephCollapse1" aria-expanded="true" aria-controls="nephCollapse1"> Do you offer 24-hour dialysis? </button></h6>\r\n</div>\r\n<div id="nephCollapse1" class="collapse" aria-labelledby="faq1" data-parent="#nephrologyFaqAccordion">\r\n<div class="card-body text-dark">Yes, for emergency cases.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#nephCollapse2" aria-expanded="false" aria-controls="nephCollapse2"> Can CKD be reversed? </button></h6>\r\n</div>\r\n<div id="nephCollapse2" class="collapse" aria-labelledby="faq2" data-parent="#nephrologyFaqAccordion">\r\n<div class="card-body text-dark">Early detection allows better management but complete reversal is rare.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#nephCollapse3" aria-expanded="false" aria-controls="nephCollapse3"> Is transplant follow-up available? </button></h6>\r\n</div>\r\n<div id="nephCollapse3" class="collapse" aria-labelledby="faq3" data-parent="#nephrologyFaqAccordion">\r\n<div class="card-body text-dark">Yes, with specialist care.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap 4.5 JS dependencies -->','\r',char(13)),'\n',char(10)),14,1,'fa-kidneys','bg-sky-50','text-sky-100','from-sky-500 to-blue-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 10:18:33','<ul><li>Hemodialysis & peritoneal dialysis</li><li>Kidney biopsy</li><li>Hypertension & electrolyte disorder management</li><li>Chronic kidney disease clinics</li><li>Post-transplant follow-up</li></ul>','<ul><li>Acute kidney injury</li><li>Chronic kidney disease</li><li>Kidney infections</li><li>Nephrotic syndrome</li><li>Polycystic kidney disease</li></ul>','<ul><li>Kidney Function Screening Package</li><li>Dialysis Care Program</li><li>Hypertension & Kidney Risk Program</li></ul>',NULL,NULL,'[{"question":"Do you offer 24-hour dialysis?","answer":"Yes, for emergency cases."},{"question":"Can CKD be reversed?","answer":"Early detection allows better management but complete reversal is rare."},{"question":"Is transplant follow-up available?","answer":"Yes, with specialist care."}]');
INSERT INTO departments VALUES(15,'Neuro Medicine','neuro-medicine','‘Dedicated to protecting what defines you — your nervous system.’','The Neurology Department diagnoses and manages disorders of the brain, spinal cord, peripheral nerves, and muscles.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f4f7f9, #e8f1f0, #dfe6f0); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Neuro Medicine</h2>\r\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;</p>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #111;">The Neurology Department diagnoses and manages disorders of the brain, spinal cord, peripheral nerves, and muscles.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>EEG, EMG, nerve conduction studies</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Stroke management &amp; rehabilitation</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Epilepsy diagnosis &amp; treatment</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Movement disorder management (Parkinson&rsquo;s)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Headache clinics</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Multiple sclerosis management</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Stroke</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Epilepsy</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Parkinson&rsquo;s disease</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Migraine &amp; chronic headaches</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Neuropathy</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="neuroFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#neuroCollapse1" aria-expanded="true" aria-controls="neuroCollapse1"> Can you help with memory loss? </button></h6>\r\n</div>\r\n<div id="neuroCollapse1" class="collapse" aria-labelledby="faq1" data-parent="#neuroFaqAccordion">\r\n<div class="card-body text-dark">Yes, we assess and manage cognitive disorders.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#neuroCollapse2" aria-expanded="false" aria-controls="neuroCollapse2"> Do you have facilities for emergency stroke care? </button></h6>\r\n</div>\r\n<div id="neuroCollapse2" class="collapse" aria-labelledby="faq2" data-parent="#neuroFaqAccordion">\r\n<div class="card-body text-dark">Yes, with 24/7 imaging and intervention.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#neuroCollapse3" aria-expanded="false" aria-controls="neuroCollapse3"> Are neurological tests painful? </button></h6>\r\n</div>\r\n<div id="neuroCollapse3" class="collapse" aria-labelledby="faq3" data-parent="#neuroFaqAccordion">\r\n<div class="card-body text-dark">Most are non-invasive and painless.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap 4.5 JS dependencies -->','\r',char(13)),'\n',char(10)),18,1,'fa-brain','bg-indigo-50','text-indigo-100','from-indigo-500 to-violet-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 10:17:46','<ul><li>EEG, EMG, nerve conduction studies</li><li>Stroke management & rehabilitation</li><li>Epilepsy diagnosis & treatment</li><li>Movement disorder management (Parkinson''s)</li><li>Headache clinics</li><li>Multiple sclerosis management</li></ul>','<ul><li>Stroke</li><li>Epilepsy</li><li>Parkinson''s disease</li><li>Migraine & chronic headaches</li><li>Neuropathy</li></ul>','',NULL,NULL,'[{"question":"Can you help with memory loss?","answer":"Yes, we assess and manage cognitive disorders."},{"question":"Do you have facilities for emergency stroke care?","answer":"Yes, with 24/7 imaging and intervention."},{"question":"Are neurological tests painful?","answer":"Most are non-invasive and painless."}]');
INSERT INTO departments VALUES(16,'Neurosurgery','neuro-surgery','‘Precision surgery for life’s most critical organ.’','The Neurosurgery Department at AMZ Hospital provides advanced surgical care for disorders affecting the brain, spine, and peripheral nerves. Our team combines precise diagnostic evaluation, cutting-edge surgical techniques, and multidisciplinary rehabilitation to ensure optimal patient outcomes. We handle both emergency neurosurgical interventions and planned procedures for complex neurological conditions.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f4f7f9, #e8f1f0, #dfe6f0); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Neuro Surgery</h2>\r\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;</p>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #111;">The Neurosurgery Department at AMZ Hospital provides advanced surgical care for disorders affecting the brain, spine, and peripheral nerves. Our team combines precise diagnostic evaluation, cutting-edge surgical techniques, and multidisciplinary rehabilitation to ensure optimal patient outcomes. We handle both emergency neurosurgical interventions and planned procedures for complex neurological conditions.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Brain tumor surgery</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Aneurysm clipping and vascular neurosurgery</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Spine surgery (disc herniation, spinal stenosis, trauma)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Minimally invasive and endoscopic neurosurgery</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Peripheral nerve surgery</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Management of head injuries and intracranial hemorrhages</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Brain tumors (benign and malignant)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Traumatic brain and spinal injuries</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Stroke-related neurosurgical conditions</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Herniated discs and spinal cord compression</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Hydrocephalus</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Peripheral nerve entrapments (carpal tunnel, ulnar nerve, etc.)</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Health Packages & FAQs -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 200px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Associated Health Packages</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Spine Screening</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Post-Stroke Surgery Evaluation</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Neuro-Rehabilitation Bundles</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 200px;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">FAQs</h5>\r\n<div id="neuroFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#neuroCollapse1" aria-expanded="true" aria-controls="neuroCollapse1"> What is the recovery time after brain or spine surgery? </button></h6>\r\n</div>\r\n<div id="neuroCollapse1" class="collapse" aria-labelledby="faq1" data-parent="#neuroFaqAccordion">\r\n<div class="card-body text-dark">Recovery depends on the procedure; minor spine surgeries take a few weeks, brain tumor surgeries may require several months.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#neuroCollapse2" aria-expanded="false" aria-controls="neuroCollapse2"> Do you offer minimally invasive neurosurgery? </button></h6>\r\n</div>\r\n<div id="neuroCollapse2" class="collapse" aria-labelledby="faq2" data-parent="#neuroFaqAccordion">\r\n<div class="card-body text-dark">Yes, minimally invasive and endoscopic techniques are available where appropriate.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#neuroCollapse3" aria-expanded="false" aria-controls="neuroCollapse3"> How is emergency neurosurgical care handled at AMZ Hospital? </button></h6>\r\n</div>\r\n<div id="neuroCollapse3" class="collapse" aria-labelledby="faq3" data-parent="#neuroFaqAccordion">\r\n<div class="card-body text-dark">A dedicated neurosurgical team is available 24/7 for emergencies.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap 4.5 JS dependencies -->','\r',char(13)),'\n',char(10)),11,1,'fa-brain','bg-purple-50','text-purple-100','from-purple-600 to-indigo-700',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 10:17:31','<ul><li>Brain tumor surgery</li><li>Aneurysm clipping and vascular neurosurgery</li><li>Spine surgery (disc herniation, spinal stenosis, trauma)</li><li>Minimally invasive and endoscopic neurosurgery</li><li>Peripheral nerve surgery</li><li>Management of head injuries and intracranial hemorrhages</li></ul>','<ul><li>Brain tumors (benign and malignant)</li><li>Traumatic brain and spinal injuries</li><li>Stroke-related neurosurgical conditions</li><li>Herniated discs and spinal cord compression</li><li>Hydrocephalus</li><li>Peripheral nerve entrapments (carpal tunnel, ulnar nerve, etc.)</li></ul>','<ul><li>Spine Screening</li><li>Post-Stroke Surgery Evaluation</li><li>Neuro-Rehabilitation Bundles</li></ul>',NULL,NULL,'[{"question":"What is the recovery time after brain or spine surgery?","answer":"Recovery depends on the procedure; minor spine surgeries take a few weeks, brain tumor surgeries may require several months."},{"question":"Do you offer minimally invasive neurosurgery?","answer":"Yes, minimally invasive and endoscopic techniques are available where appropriate."},{"question":"How is emergency neurosurgical care handled at AMZ Hospital?","answer":"A dedicated neurosurgical team is available 24/7 for emergencies."}]');
INSERT INTO departments VALUES(17,'Orthopedic','orthopedics','Because movement is life — and we help you move freely.','The Orthopedic Surgery Department at AMZ Hospital Ltd. provides comprehensive care for musculoskeletal conditions, including fractures, joint disorders, sports injuries, and spinal problems. Our orthopedic surgeons specialize in joint replacement, arthroscopy, trauma surgery, and minimally invasive procedures, aiming for faster recovery and restored mobility.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Orthopedic Surgery</h2>\r\n<h6 style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;</h6>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">The Orthopedic Surgery Department at AMZ Hospital Ltd. provides comprehensive care for musculoskeletal conditions, including fractures, joint disorders, sports injuries, and spinal problems. Our orthopedic surgeons specialize in joint replacement, arthroscopy, trauma surgery, and minimally invasive procedures, aiming for faster recovery and restored mobility.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 260px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Joint replacement surgery (hip, knee, shoulder)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Arthroscopy</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Fracture management</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Sports injury treatment</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Spine surgery</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Pediatric orthopedic care</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 260px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Arthritis</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Sports injuries</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Fractures &amp; dislocations</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Disc herniation</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Osteoporosis</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Associated Health Packages -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef6f7, #e0f7fa); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Associated Health Packages</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-primary mr-2">✔ </span>Bone &amp; Joint Health Check</li>\r\n<li class="mb-2"><span class="text-primary mr-2">✔ </span>Sports Injury Recovery Program</li>\r\n<li class="mb-2"><span class="text-primary mr-2">✔ </span>Arthritis Care Package</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="orthopedicFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="orf1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#orCollapse1" aria-expanded="true" aria-controls="orCollapse1"> Do you offer minimally invasive joint surgery? </button></h6>\r\n</div>\r\n<div id="orCollapse1" class="collapse" aria-labelledby="orf1" data-parent="#orthopedicFaqAccordion">\r\n<div class="card-body text-dark">Yes, minimally invasive joint surgery is offered for select cases, ensuring quicker recovery and less discomfort.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="orf2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#orCollapse2" aria-expanded="false" aria-controls="orCollapse2"> Is physiotherapy available on-site? </button></h6>\r\n</div>\r\n<div id="orCollapse2" class="collapse" aria-labelledby="orf2" data-parent="#orthopedicFaqAccordion">\r\n<div class="card-body text-dark">Yes, physiotherapy is available on-site for post-operative care and injury rehabilitation.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="orf3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#orCollapse3" aria-expanded="false" aria-controls="orCollapse3"> Can you treat children&rsquo;s bone issues? </button></h6>\r\n</div>\r\n<div id="orCollapse3" class="collapse" aria-labelledby="orf3" data-parent="#orthopedicFaqAccordion">\r\n<div class="card-body text-dark">Yes, we have pediatric orthopedic expertise to manage bone and joint conditions in children.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap JS dependencies -->','\r',char(13)),'\n',char(10)),10,1,'fa-bone','bg-stone-50','text-stone-100','from-stone-500 to-slate-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 10:00:27','<ul><li>Joint replacement surgery (hip, knee, shoulder)</li><li>Arthroscopy</li><li>Fracture management</li><li>Sports injury treatment</li><li>Spine surgery</li><li>Pediatric orthopedic care</li></ul>','<ul><li>Arthritis</li><li>Sports injuries</li><li>Fractures & dislocations</li><li>Disc herniation</li><li>Osteoporosis</li></ul>','<ul><li>Bone & Joint Health Check</li><li>Sports Injury Recovery Program</li><li>Arthritis Care Package</li></ul>',NULL,NULL,'[{"question":"Do you offer minimally invasive joint surgery?","answer":"Yes, minimally invasive joint surgery is offered for select cases, ensuring quicker recovery and less discomfort."},{"question":"Is physiotherapy available on-site?","answer":"Yes, physiotherapy is available on-site for post-operative care and injury rehabilitation."},{"question":"Can you treat children''s bone issues?","answer":"Yes, we have pediatric orthopedic expertise to manage bone and joint conditions in children."}]');
INSERT INTO departments VALUES(18,'Pediatric','pediatric','Caring for today’s children — building tomorrow’s health.','The Pediatrics Department at AMZ Hospital Ltd. is dedicated to the health and well-being of infants, children, and adolescents. Our pediatricians offer preventive care, growth and development monitoring, vaccination, and treatment of acute and chronic childhood illnesses. With child-friendly facilities and a compassionate approach, we ensure the best start for every child''s life.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 220px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Pediatrics</h2>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">The Pediatrics Department at AMZ Hospital Ltd. is dedicated to the health and well-being of infants, children, and adolescents. Our pediatricians offer preventive care, growth and development monitoring, vaccination, and treatment of acute and chronic childhood illnesses. With child-friendly facilities and a compassionate approach, we ensure the best start for every child&rsquo;s life.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Well-baby checkups &amp; immunizations</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Developmental assessment &amp; monitoring</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Pediatric infectious disease management</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Asthma &amp; allergy care</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Neonatal follow-up</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Pediatric nutrition counseling</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Common childhood infections (respiratory, GI)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Growth and nutritional issues</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Neonatal and developmental concerns</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Gastroenteritis &amp; dehydration</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Associated Health Packages Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Associated Health Packages</h5>\r\n<ul class="list-unstyled mb-0">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Child Wellness Package</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Immunization Package</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Pediatric Asthma Management Plan</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="pediatricsFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="pf1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#pediatricsCollapse1" aria-expanded="true" aria-controls="pediatricsCollapse1">What vaccinations are offered through pediatric packages?</button></h6>\r\n</div>\r\n<div id="pediatricsCollapse1" class="collapse" aria-labelledby="pf1" data-parent="#pediatricsFaqAccordion">\r\n<div class="card-body text-dark">All EPI vaccines and additional recommended vaccines are provided based on age and health requirements.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="pf2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#pediatricsCollapse2" aria-expanded="false" aria-controls="pediatricsCollapse2">How to book a pediatric consultation?</button></h6>\r\n</div>\r\n<div id="pediatricsCollapse2" class="collapse" aria-labelledby="pf2" data-parent="#pediatricsFaqAccordion">\r\n<div class="card-body text-dark">Appointments can be booked via our website, call center, or in-person at the pediatric department.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="pf3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#pediatricsCollapse3" aria-expanded="false" aria-controls="pediatricsCollapse3">Emergency pediatric services available?</button></h6>\r\n</div>\r\n<div id="pediatricsCollapse3" class="collapse" aria-labelledby="pf3" data-parent="#pediatricsFaqAccordion">\r\n<div class="card-body text-dark">Yes, we have a pediatric ICU and emergency services for critical cases.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap JS dependencies -->','\r',char(13)),'\n',char(10)),5,1,'fa-baby','bg-amber-50','text-amber-100','from-amber-500 to-yellow-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 05:40:56','<ul><li>Well-baby checkups & immunizations</li><li>Developmental assessment & monitoring</li><li>Pediatric infectious disease management</li><li>Asthma & allergy care</li><li>Neonatal follow-up</li><li>Pediatric nutrition counseling</li></ul>','<ul><li>Common childhood infections (respiratory, GI)</li><li>Growth and nutritional issues</li><li>Neonatal and developmental concerns</li><li>Gastroenteritis & dehydration</li></ul>','<ul><li>Child Wellness Package</li><li>Immunization Package</li><li>Pediatric Asthma Management Plan</li></ul>',NULL,NULL,'[{"question":"What vaccinations are offered through pediatric packages?","answer":"All EPI vaccines and additional recommended vaccines are provided based on age and health requirements."},{"question":"How to book a pediatric consultation?","answer":"Appointments can be booked via our website, call center, or in-person at the pediatric department."},{"question":"Emergency pediatric services available?","answer":"Yes, we have a pediatric ICU and emergency services for critical cases."}]');
INSERT INTO departments VALUES(19,'Pediatric Surgeon','pediatric-surgeon','Small patients, big care.','The Pediatric Surgery Department provides surgical care tailored to infants, children, and adolescents, with a focus on safety, precision, and minimal discomfort. Our pediatric surgeons are trained to handle a wide range of congenital and acquired surgical conditions.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 220px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Pediatric Surgery</h2>\r\n<h6 style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;</h6>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">The Pediatric Surgery Department provides surgical care tailored to infants, children, and adolescents, with a focus on safety, precision, and minimal discomfort. Our pediatric surgeons are trained to handle a wide range of congenital and acquired surgical conditions.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Congenital anomaly correction</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Hernia and hydrocele repair</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Pediatric gastrointestinal surgeries</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Circumcision and urological surgeries</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Minimally invasive pediatric procedures</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Cleft lip and palate</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Undescended testes</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Pediatric tumors</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Intestinal malformations</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Appendicitis in children</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="pediatricSurgeryFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="psf1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#psCollapse1" aria-expanded="true" aria-controls="psCollapse1"> What is the minimum age for pediatric surgery? </button></h6>\r\n</div>\r\n<div id="psCollapse1" class="collapse" aria-labelledby="psf1" data-parent="#pediatricSurgeryFaqAccordion">\r\n<div class="card-body text-dark">The minimum age depends on the condition; surgeries can be performed even on newborns if medically required.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="psf2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#psCollapse2" aria-expanded="false" aria-controls="psCollapse2"> Are all procedures done under general anesthesia? </button></h6>\r\n</div>\r\n<div id="psCollapse2" class="collapse" aria-labelledby="psf2" data-parent="#pediatricSurgeryFaqAccordion">\r\n<div class="card-body text-dark">Most procedures are performed under general anesthesia for safety and comfort, but some minor cases may use local anesthesia.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="psf3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#psCollapse3" aria-expanded="false" aria-controls="psCollapse3"> How can parents prepare their child for surgery? </button></h6>\r\n</div>\r\n<div id="psCollapse3" class="collapse" aria-labelledby="psf3" data-parent="#pediatricSurgeryFaqAccordion">\r\n<div class="card-body text-dark">Parents are guided with instructions on fasting, medication adjustments, and psychological preparation to ease the child&rsquo;s experience.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap JS dependencies -->','\r',char(13)),'\n',char(10)),9,1,'fa-child','bg-yellow-50','text-yellow-100','from-yellow-500 to-orange-500',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 10:00:48','<ul><li>Congenital anomaly correction</li><li>Hernia and hydrocele repair</li><li>Pediatric gastrointestinal surgeries</li><li>Circumcision and urological surgeries</li><li>Minimally invasive pediatric procedures</li></ul>','<ul><li>Cleft lip and palate</li><li>Undescended testes</li><li>Pediatric tumors</li><li>Intestinal malformations</li><li>Appendicitis in children</li></ul>','',NULL,NULL,'[{"question":"What is the minimum age for pediatric surgery?","answer":"The minimum age depends on the condition; surgeries can be performed even on newborns if medically required."},{"question":"Are all procedures done under general anesthesia?","answer":"Most procedures are performed under general anesthesia for safety and comfort, but some minor cases may use local anesthesia."},{"question":"How can parents prepare their child for surgery?","answer":"Parents are guided with instructions on fasting, medication adjustments, and psychological preparation to ease the child''s experience."}]');
INSERT INTO departments VALUES(20,'Physical Medicine & Rehabilitation','physical-medicine-&-rehabilitation','NULL','We focus on restoring movement, function, and quality of life for patients recovering from injury, illness, or surgery. We provide individualized rehabilitation programs combining medical care, therapeutic exercises, and advanced rehabilitation technologies to maximize recovery outcomes. Our multidisciplinary approach integrates physicians, physiotherapists, occupational therapists, and speech therapists to ensure comprehensive patient care.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Physical Medicine &amp; Rehabilitation</h2>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">We focus on restoring movement, function, and quality of life for patients recovering from injury, illness, or surgery. We provide individualized rehabilitation programs combining medical care, therapeutic exercises, and advanced rehabilitation technologies to maximize recovery outcomes. Our multidisciplinary approach integrates physicians, physiotherapists, occupational therapists, and speech therapists to ensure comprehensive patient care.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Physiotherapy for musculoskeletal, neurological, and post-surgical conditions</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Pain management (non-surgical) for back pain, neck pain, arthritis, and sports injuries</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Stroke rehabilitation to improve mobility, balance, and daily functioning</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Post-orthopedic surgery rehabilitation (hip, knee, spine, shoulder)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Neurological rehabilitation (spinal cord injury, Parkinson&rsquo;s, multiple sclerosis)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Pediatric rehabilitation for developmental and motor function issues</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Speech and swallowing therapy for post-stroke or neurological conditions</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Occupational therapy to improve daily activity performance</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Gait training and balance therapy</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Electrotherapy &amp; therapeutic ultrasound for pain relief and muscle stimulation</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Stroke and paralysis recovery</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Sports injuries and ligament tears</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Chronic back pain, neck pain, and joint disorders</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Cerebral palsy and other pediatric developmental disorders</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Post-surgical stiffness or weakness</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Osteoarthritis and rheumatoid arthritis-related disability</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Neuropathies and nerve injuries</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Post-fracture or immobilization complications</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="rehabFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="rf1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#rehabCollapse1" aria-expanded="true" aria-controls="rehabCollapse1"> How soon after surgery should I start rehabilitation? </button></h6>\r\n</div>\r\n<div id="rehabCollapse1" class="collapse" aria-labelledby="rf1" data-parent="#rehabFaqAccordion">\r\n<div class="card-body text-dark">It depends on the surgery type; your physician will guide the safe start time.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="rf2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#rehabCollapse2" aria-expanded="false" aria-controls="rehabCollapse2"> Do you provide home-based therapy services? </button></h6>\r\n</div>\r\n<div id="rehabCollapse2" class="collapse" aria-labelledby="rf2" data-parent="#rehabFaqAccordion">\r\n<div class="card-body text-dark">Yes, home-based therapy is available in select cases.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="rf3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#rehabCollapse3" aria-expanded="false" aria-controls="rehabCollapse3"> How long will my rehabilitation program last? </button></h6>\r\n</div>\r\n<div id="rehabCollapse3" class="collapse" aria-labelledby="rf3" data-parent="#rehabFaqAccordion">\r\n<div class="card-body text-dark">Duration varies by condition and goals; typically several weeks to months.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap JS dependencies -->','\r',char(13)),'\n',char(10)),27,1,'fa-person-walking','bg-teal-50','text-teal-100','from-teal-500 to-cyan-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 10:17:01','<ul><li>Physiotherapy for musculoskeletal, neurological, and post-surgical conditions</li><li>Pain management (non-surgical) for back pain, neck pain, arthritis, and sports injuries</li><li>Stroke rehabilitation to improve mobility, balance, and daily functioning</li><li>Post-orthopedic surgery rehabilitation (hip, knee, spine, shoulder)</li><li>Neurological rehabilitation (spinal cord injury, Parkinson''s, multiple sclerosis)</li><li>Pediatric rehabilitation for developmental and motor function issues</li><li>Speech and swallowing therapy for post-stroke or neurological conditions</li><li>Occupational therapy to improve daily activity performance</li><li>Gait training and balance therapy</li><li>Electrotherapy & therapeutic ultrasound for pain relief and muscle stimulation</li></ul>','<ul><li>Stroke and paralysis recovery</li><li>Sports injuries and ligament tears</li><li>Chronic back pain, neck pain, and joint disorders</li><li>Cerebral palsy and other pediatric developmental disorders</li><li>Post-surgical stiffness or weakness</li><li>Osteoarthritis and rheumatoid arthritis-related disability</li><li>Neuropathies and nerve injuries</li><li>Post-fracture or immobilization complications</li></ul>','',NULL,NULL,'[{"question":"How soon after surgery should I start rehabilitation?","answer":"It depends on the surgery type; your physician will guide the safe start time."},{"question":"Do you provide home-based therapy services?","answer":"Yes, home-based therapy is available in select cases."},{"question":"How long will my rehabilitation program last?","answer":"Duration varies by condition and goals; typically several weeks to months."}]');
INSERT INTO departments VALUES(21,'Plastic, Aesthetic & Laser Surgery','plastic,-aesthetic-&-laser-surgery','Where science meets art for a beautiful healing','The Plastic, Aesthetic & Laser Surgery Department at AMZ Hospital offers advanced surgical and non-surgical solutions to restore form, enhance beauty, and improve quality of life. Our expert surgeons combine medical precision with artistic finesse, ensuring safe, effective, and natural-looking results. Services range from reconstructive surgeries for trauma and congenital deformities to aesthetic enhancements using cutting-edge laser technology.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 220px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Plastic, Aesthetic &amp; Laser Surgery</h2>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">The Plastic, Aesthetic &amp; Laser Surgery Department at AMZ Hospital offers advanced surgical and non-surgical solutions to restore form, enhance beauty, and improve quality of life. Our expert surgeons combine medical precision with artistic finesse, ensuring safe, effective, and natural-looking results. Services range from reconstructive surgeries for trauma and congenital deformities to aesthetic enhancements using cutting-edge laser technology.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Reconstructive surgery for burns, trauma, and congenital anomalies</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Cosmetic facial and body contouring procedures</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Laser treatments for skin rejuvenation, pigmentation, and scar reduction</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Hair restoration and transplant</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Scar revision and keloid management</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Post-burn contractures</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Congenital anomalies (e.g., cleft lip/palate)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Acne scars and pigmentation disorders</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Excess skin and fat deposits</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓ </span>Benign skin growths and moles</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Associated Health Packages Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Associated Health Packages</h5>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">To be defined.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="plasticFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="pf1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#plasticCollapse1" aria-expanded="true" aria-controls="plasticCollapse1">What&rsquo;s the recovery time for common plastic surgery procedures?</button></h6>\r\n</div>\r\n<div id="plasticCollapse1" class="collapse" aria-labelledby="pf1" data-parent="#plasticFaqAccordion">\r\n<div class="card-body text-dark">Recovery depends on procedure type; minor procedures may take a few days, while major surgeries can take several weeks.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="pf2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#plasticCollapse2" aria-expanded="false" aria-controls="plasticCollapse2">Are the results of laser treatments permanent?</button></h6>\r\n</div>\r\n<div id="plasticCollapse2" class="collapse" aria-labelledby="pf2" data-parent="#plasticFaqAccordion">\r\n<div class="card-body text-dark">Results are long-lasting but may require maintenance sessions depending on the condition and skin type.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="pf3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#plasticCollapse3" aria-expanded="false" aria-controls="plasticCollapse3">Do you offer minimally invasive options?</button></h6>\r\n</div>\r\n<div id="plasticCollapse3" class="collapse" aria-labelledby="pf3" data-parent="#plasticFaqAccordion">\r\n<div class="card-body text-dark">Yes, many procedures are minimally invasive to reduce recovery time and scarring.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap JS dependencies -->','\r',char(13)),'\n',char(10)),8,1,'fa-wand-magic-sparkles','bg-fuchsia-50','text-fuchsia-100','from-pink-500 to-purple-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 10:00:09','<ul><li>Reconstructive surgery for burns, trauma, and congenital anomalies</li><li>Cosmetic facial and body contouring procedures</li><li>Laser treatments for skin rejuvenation, pigmentation, and scar reduction</li><li>Hair restoration and transplant</li><li>Scar revision and keloid management</li></ul>','<ul><li>Post-burn contractures</li><li>Congenital anomalies (e.g., cleft lip/palate)</li><li>Acne scars and pigmentation disorders</li><li>Excess skin and fat deposits</li><li>Benign skin growths and moles</li></ul>','<ul><li>To be defined.</li></ul>',NULL,NULL,'[{"question":"What''s the recovery time for common plastic surgery procedures?","answer":"Recovery depends on procedure type; minor procedures may take a few days, while major surgeries can take several weeks."},{"question":"Are the results of laser treatments permanent?","answer":"Results are long-lasting but may require maintenance sessions depending on the condition and skin type."},{"question":"Do you offer minimally invasive options?","answer":"Yes, many procedures are minimally invasive to reduce recovery time and scarring."}]');
INSERT INTO departments VALUES(22,'Psychiatrist','psychiatrist','‘Healing the mind is the first step to healing the body.','The Psychiatry Department provides mental health evaluation, therapy, and medication management for a wide range of psychiatric conditions.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Psychiatry</h2>\r\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;</p>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #111;">The Psychiatry Department provides mental health evaluation, therapy, and medication management for a wide range of psychiatric conditions.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Individual &amp; group psychotherapy</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Medication management</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Addiction counseling</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Child &amp; adolescent psychiatry</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Crisis intervention</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Depression</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Anxiety disorders</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Bipolar disorder</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Schizophrenia</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Substance use disorders</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="psychiatryFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="pf1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#psychiatryCollapse1" aria-expanded="true" aria-controls="psychiatryCollapse1"> Do you offer counseling only? </button></h6>\r\n</div>\r\n<div id="psychiatryCollapse1" class="collapse" aria-labelledby="pf1" data-parent="#psychiatryFaqAccordion">\r\n<div class="card-body text-dark">Yes, for those who prefer non-medication approaches.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="pf2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#psychiatryCollapse2" aria-expanded="false" aria-controls="psychiatryCollapse2"> Is confidentiality assured? </button></h6>\r\n</div>\r\n<div id="psychiatryCollapse2" class="collapse" aria-labelledby="pf2" data-parent="#psychiatryFaqAccordion">\r\n<div class="card-body text-dark">Absolutely.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="pf3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#psychiatryCollapse3" aria-expanded="false" aria-controls="psychiatryCollapse3"> Do you treat children? </button></h6>\r\n</div>\r\n<div id="psychiatryCollapse3" class="collapse" aria-labelledby="pf3" data-parent="#psychiatryFaqAccordion">\r\n<div class="card-body text-dark">Yes, with specialized pediatric mental health care.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap 4.5 JS dependencies -->','\r',char(13)),'\n',char(10)),25,1,'fa-head-side-virus','bg-violet-50','text-violet-100','from-violet-500 to-indigo-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 10:18:08','<ul><li>Individual & group psychotherapy</li><li>Medication management</li><li>Addiction counseling</li><li>Child & adolescent psychiatry</li><li>Crisis intervention</li></ul>','<ul><li>Depression</li><li>Anxiety disorders</li><li>Bipolar disorder</li><li>Schizophrenia</li><li>Substance use disorders</li></ul>','',NULL,NULL,'[{"question":"Do you offer counseling only?","answer":"Yes, for those who prefer non-medication approaches."},{"question":"Is confidentiality assured?","answer":"Absolutely."},{"question":"Do you treat children?","answer":"Yes, with specialized pediatric mental health care."}]');
INSERT INTO departments VALUES(23,'Respiratory And Medicine','respiratory-and-medicine','Breathe easy — we are here for your lungs.','The Pulmonology Department diagnoses and treats diseases of the lungs and respiratory system, offering both inpatient and outpatient care.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Respiratory &amp; Asthma</h2>\r\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">(Pulmonology/ Respiratory Medicine)</p>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #111;">&nbsp;The Pulmonology Department diagnoses and treats diseases of the lungs and respiratory system, offering both inpatient and outpatient care.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Pulmonary function testing</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Bronchoscopy</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Sleep apnea studies</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Asthma management programs</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Tuberculosis treatment</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Oxygen therapy &amp; respiratory rehabilitation</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Asthma</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Chronic obstructive pulmonary disease (COPD)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Pneumonia</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Tuberculosis</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Sleep apnea</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="respFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#respCollapse1" aria-expanded="true" aria-controls="respCollapse1"> Do you provide TB treatment? </button></h6>\r\n</div>\r\n<div id="respCollapse1" class="collapse" aria-labelledby="faq1" data-parent="#respFaqAccordion">\r\n<div class="card-body text-dark">Yes, as per national guidelines.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#respCollapse2" aria-expanded="false" aria-controls="respCollapse2"> Is spirometry available? </button></h6>\r\n</div>\r\n<div id="respCollapse2" class="collapse" aria-labelledby="faq2" data-parent="#respFaqAccordion">\r\n<div class="card-body text-dark">Yes, for diagnosis and monitoring.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#respCollapse3" aria-expanded="false" aria-controls="respCollapse3"> Do you treat sleep disorders? </button></h6>\r\n</div>\r\n<div id="respCollapse3" class="collapse" aria-labelledby="faq3" data-parent="#respFaqAccordion">\r\n<div class="card-body text-dark">Yes, including sleep apnea.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap 4.5 JS dependencies -->','\r',char(13)),'\n',char(10)),19,1,'fa-lungs','bg-cyan-50','text-cyan-100','from-sky-500 to-cyan-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 09:59:14','<ul><li>Pulmonary function testing</li><li>Bronchoscopy</li><li>Sleep apnea studies</li><li>Asthma management programs</li><li>Tuberculosis treatment</li><li>Oxygen therapy & respiratory rehabilitation</li></ul>','<ul><li>Asthma</li><li>Chronic obstructive pulmonary disease (COPD)</li><li>Pneumonia</li><li>Tuberculosis</li><li>Sleep apnea</li></ul>','',NULL,NULL,'[{"question":"Do you provide TB treatment?","answer":"Yes, as per national guidelines."},{"question":"Is spirometry available?","answer":"Yes, for diagnosis and monitoring."},{"question":"Do you treat sleep disorders?","answer":"Yes, including sleep apnea."}]');
INSERT INTO departments VALUES(24,'Thoracic Surgery','thoracic-surgery','‘Expert care for the body’s breathing system.’','The Department specializes in surgical treatment of diseases affecting the lungs, esophagus, chest wall, and mediastinum. Care is provided for both complex elective cases and life-threatening emergencies.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f4f7f9, #e8f1f0, #dfe6f0); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Thoracic Surgery</h2>\r\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;</p>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #111;">The Department specializes in surgical treatment of diseases affecting the lungs, esophagus, chest wall, and mediastinum. Care is provided for both complex elective cases and life-threatening emergencies.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Lobectomy, pneumonectomy, segmentectomy</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Esophagectomy (including Ivor Lewis procedure)</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Chest wall tumor resection</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Video-Assisted Thoracoscopic Surgery (VATS)</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Bronchial and mediastinal surgeries</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Lung cancer &amp; benign lung diseases</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Esophageal cancer &amp; motility disorders</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Chest wall tumors &amp; deformities</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Complex pleural diseases (empyema, pneumothorax)</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Health Packages & FAQs -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 200px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Associated Health Packages</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Preoperative Thoracic Surgery Assessment Package</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Lung Cancer Screening &amp; Surgical Planning</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Postoperative Recovery &amp; Rehabilitation Package</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 200px;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">FAQs</h5>\r\n<div id="thoracicFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#thorCollapse1" aria-expanded="true" aria-controls="thorCollapse1"> What are the risks of thoracic surgery? </button></h6>\r\n</div>\r\n<div id="thorCollapse1" class="collapse" aria-labelledby="faq1" data-parent="#thoracicFaqAccordion">\r\n<div class="card-body text-dark">Risks vary by procedure and patient condition; surgeons discuss pre-op risk assessment.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#thorCollapse2" aria-expanded="false" aria-controls="thorCollapse2"> How long is the recovery period after lung surgery? </button></h6>\r\n</div>\r\n<div id="thorCollapse2" class="collapse" aria-labelledby="faq2" data-parent="#thoracicFaqAccordion">\r\n<div class="card-body text-dark">Recovery depends on the surgery type; generally 4-8 weeks for full recovery.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#thorCollapse3" aria-expanded="false" aria-controls="thorCollapse3"> Does AMZ Hospital offer minimally invasive thoracic surgery? </button></h6>\r\n</div>\r\n<div id="thorCollapse3" class="collapse" aria-labelledby="faq3" data-parent="#thoracicFaqAccordion">\r\n<div class="card-body text-dark">Yes, including VATS and other minimally invasive techniques.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap 4.5 JS dependencies -->','\r',char(13)),'\n',char(10)),15,1,'fa-lungs','bg-slate-50','text-slate-100','from-slate-600 to-gray-700',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 09:58:55','<ul><li>Lobectomy, pneumonectomy, segmentectomy</li><li>Esophagectomy (including Ivor Lewis procedure)</li><li>Chest wall tumor resection</li><li>Video-Assisted Thoracoscopic Surgery (VATS)</li><li>Bronchial and mediastinal surgeries</li></ul>','<ul><li>Lung cancer & benign lung diseases</li><li>Esophageal cancer & motility disorders</li><li>Chest wall tumors & deformities</li><li>Complex pleural diseases (empyema, pneumothorax)</li></ul>','<ul><li>Preoperative Thoracic Surgery Assessment Package</li><li>Lung Cancer Screening & Surgical Planning</li><li>Postoperative Recovery & Rehabilitation Package</li></ul>',NULL,NULL,'[{"question":"What are the risks of thoracic surgery?","answer":"Risks vary by procedure and patient condition; surgeons discuss pre-op risk assessment."},{"question":"How long is the recovery period after lung surgery?","answer":"Recovery depends on the surgery type; generally 4-8 weeks for full recovery."},{"question":"Does AMZ Hospital offer minimally invasive thoracic surgery?","answer":"Yes, including VATS and other minimally invasive techniques."}]');
INSERT INTO departments VALUES(25,'Urology Specialist','urology-specialist','NULL',NULL,replace(' <p class="pbmit-firstletter">\n        Main Hospitals or larger hospital systems may provide their own ambulance service as a service to the community, or where ambulance care is unreliable or chargeable. Many hospital-based EMS departments operate solely with their hospital\n     </p>\n     <p>The physicians will attempt to treat casualties at the scene and will only transport them to hospital if it is deemed necessary. If patients are transported to hospital, they are more likely to go straight to a ward rather than to <u>an emergency department</u> . Countries that use this model include Austria, France, Belgium, Luxembourg, Italy, Spain, Brazil and Chile.</p>\n     <div class="row">\n        <div class="col-md-6">\n           <ul class="list-group list-group-borderless">\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">That extremely painful or again is there anyone.</span>\n              </li>\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">Indignation and dislike men who are so beguiled</span>\n              </li>\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">Desires these cases are perfectly simple easy distinguish.</span>\n              </li>\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">That extremely painful or again that is there anyone.</span>\n              </li>\n           </ul>\n        </div>\n        <div class="col-md-6">\n           <ul class="list-group list-group-borderless">\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">Starchy foods are a key food group in healthy eating</span>\n              </li>\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">People are sleeping much less than they did in the past</span>\n              </li>\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">Don’t smoke or use drugs, and only drink in moderation</span>\n              </li>\n              <li class="list-group-item">\n                 <span class="pbmit-icon-list-icon">\n                    <i aria-hidden="true" class="ti-check"></i>\n                 </span>\n                 <span class="pbmit-icon-list-text">Your body is full of trillions of bacteria, viruses and fungi</span>\n              </li>\n           </ul>\n        </div>\n     </div>','\n',char(10)),0,0,'fa-kidneys','bg-blue-50','text-blue-100','from-blue-500 to-cyan-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 04:42:58',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO departments VALUES(26,'Vascular Surgeon','vascular-surgeon','‘Healthy circulation, healthier life.’','The Vascular Surgery Department at AMZ Hospital specializes in diagnosing, treating, and managing diseases affecting the arteries, veins, and lymphatic vessels. Our expert surgeons combine advanced surgical techniques with minimally invasive interventions to restore proper blood flow and prevent complications.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f7f9fa, #e8f0f2); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Vascular Surgery</h2>\r\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;</p>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #111;">The Vascular Surgery Department at AMZ Hospital specializes in diagnosing, treating, and managing diseases affecting the arteries, veins, and lymphatic vessels. Our expert surgeons combine advanced surgical techniques with minimally invasive interventions to restore proper blood flow and prevent complications.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Endovascular surgery (minimally invasive vessel repair)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Bypass surgery for blocked arteries</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Varicose vein treatment (surgical &amp; laser)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Carotid artery surgery</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Dialysis access creation &amp; maintenance (AV fistula, graft)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Aneurysm repair (open &amp; endovascular)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Thrombectomy &amp; clot removal</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Management of vascular trauma</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Peripheral artery disease (PAD)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Varicose veins &amp; chronic venous insufficiency</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Deep vein thrombosis (DVT)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Aneurysms (aortic &amp; peripheral)</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Carotid artery stenosis</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Vascular complications from diabetes</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Blood clot-related disorders</li>\r\n<li class="mb-2"><span class="text-success mr-2">✓</span>Lymphedema</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- FAQ Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f0f4f6, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: auto;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Departmental FAQs</h5>\r\n<div id="vascularFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="vf1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#vascularCollapse1" aria-expanded="true" aria-controls="vascularCollapse1"> How do I know if I have a vascular condition? </button></h6>\r\n</div>\r\n<div id="vascularCollapse1" class="collapse" aria-labelledby="vf1" data-parent="#vascularFaqAccordion">\r\n<div class="card-body text-dark">Symptoms include leg pain, swelling, numbness, cold extremities, or varicose veins. Diagnostic tests confirm conditions.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="vf2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#vascularCollapse2" aria-expanded="false" aria-controls="vascularCollapse2"> Are all vascular surgeries open procedures? </button></h6>\r\n</div>\r\n<div id="vascularCollapse2" class="collapse" aria-labelledby="vf2" data-parent="#vascularFaqAccordion">\r\n<div class="card-body text-dark">No, many procedures are minimally invasive or endovascular depending on patient needs.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="vf3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#vascularCollapse3" aria-expanded="false" aria-controls="vascularCollapse3"> Is vascular surgery safe for elderly patients? </button></h6>\r\n</div>\r\n<div id="vascularCollapse3" class="collapse" aria-labelledby="vf3" data-parent="#vascularFaqAccordion">\r\n<div class="card-body text-dark">Yes, preoperative assessment and careful monitoring make surgeries safe for older patients.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap 4.5 JS dependencies -->','\r',char(13)),'\n',char(10)),24,1,'fa-heart-circle-check','bg-red-50','text-red-100','from-red-500 to-rose-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 09:57:34','<ul><li>Endovascular surgery (minimally invasive vessel repair)</li><li>Bypass surgery for blocked arteries</li><li>Varicose vein treatment (surgical & laser)</li><li>Carotid artery surgery</li><li>Dialysis access creation & maintenance (AV fistula, graft)</li><li>Aneurysm repair (open & endovascular)</li><li>Thrombectomy & clot removal</li><li>Management of vascular trauma</li></ul>','<ul><li>Peripheral artery disease (PAD)</li><li>Varicose veins & chronic venous insufficiency</li><li>Deep vein thrombosis (DVT)</li><li>Aneurysms (aortic & peripheral)</li><li>Carotid artery stenosis</li><li>Vascular complications from diabetes</li><li>Blood clot-related disorders</li><li>Lymphedema</li></ul>','',NULL,NULL,'[{"question":"How do I know if I have a vascular condition?","answer":"Symptoms include leg pain, swelling, numbness, cold extremities, or varicose veins. Diagnostic tests confirm conditions."},{"question":"Are all vascular surgeries open procedures?","answer":"No, many procedures are minimally invasive or endovascular depending on patient needs."},{"question":"Is vascular surgery safe for elderly patients?","answer":"Yes, preoperative assessment and careful monitoring make surgeries safe for older patients."}]');
