INSERT INTO departments VALUES(30,'Urology','urology','‘Advanced solutions for urinary & men’s health.’','The Urology Department provides surgical and medical care for urinary tract disorders in men and women, as well as male reproductive health.',replace(replace('<div class="container">\r\n<div class="row"><!-- Full-width Intro Card -->\r\n<div class="col-12 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #f4f7f9, #e8f1f0, #dfe6f0); color: #111; backdrop-filter: blur(8px); width: 100%; height: 250px;">\r\n<div class="card-body">\r\n<h2 class="font-weight-bold mb-2" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Urology</h2>\r\n<p class="font-italic mb-3" style="font-family: ''Calibri'', sans-serif; color: #1a3a5a;">&nbsp;</p>\r\n<p style="font-family: ''Calibri'', sans-serif; color: #111;">The Urology Department provides surgical and medical care for urinary tract disorders in men and women, as well as male reproductive health.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Key Services & Common Conditions -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Key Services &amp; Procedures</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Kidney stone removal (PCNL, ureteroscopy)</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Prostate surgery (TURP, laser)</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Bladder surgery</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Urethral reconstruction</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Male infertility treatment</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 300px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Common Conditions Treated</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><strong><span class="text-success mr-2">✓ </span></strong>Kidney &amp; bladder stones</li>\r\n<li class="mb-2"><strong><span class="text-success mr-2">✓ </span></strong>Prostate enlargement (BPH)</li>\r\n<li class="mb-2"><strong><span class="text-success mr-2">✓ </span></strong>Urinary incontinence</li>\r\n<li class="mb-2"><strong><span class="text-success mr-2">✓ </span></strong>Urinary tract infections</li>\r\n<li class="mb-2"><strong><span class="text-success mr-2">✓ </span></strong>Male infertility</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Two-column Cards: Health Packages & FAQs -->\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 200px;">\r\n<div class="card-body d-flex flex-column">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">Associated Health Packages</h5>\r\n<ul class="list-unstyled mb-0 flex-grow-1">\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Prostate Health Check</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Kidney Stone Prevention Program</li>\r\n<li class="mb-2"><span class="text-success mr-2"><strong>✓</strong> </span>Male Fertility Evaluation Package</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div class="col-md-6 mb-4 d-flex">\r\n<div class="card shadow-sm h-100" style="border-radius: 12px; background: linear-gradient(135deg, #ffffff, #eef2f3, #e0f2f1); color: #111; backdrop-filter: blur(8px); width: 100%; height: 200px;">\r\n<div class="card-body">\r\n<h5 class="font-weight-bold mb-3" style="font-family: ''Calibri'', sans-serif; color: #0a1f44;">FAQs</h5>\r\n<div id="urologyFaqAccordion">\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq1" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#urologyCollapse1" aria-expanded="true" aria-controls="urologyCollapse1"> Do you treat female urinary issues? </button></h6>\r\n</div>\r\n<div id="urologyCollapse1" class="collapse" aria-labelledby="faq1" data-parent="#urologyFaqAccordion">\r\n<div class="card-body text-dark">Yes, including incontinence.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq2" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#urologyCollapse2" aria-expanded="false" aria-controls="urologyCollapse2"> Is laser surgery available for prostate? </button></h6>\r\n</div>\r\n<div id="urologyCollapse2" class="collapse" aria-labelledby="faq2" data-parent="#urologyFaqAccordion">\r\n<div class="card-body text-dark">Yes, minimally invasive options are available.</div>\r\n</div>\r\n</div>\r\n<div class="card mb-2 bg-transparent text-dark" style="border: none;">\r\n<div id="faq3" class="card-header p-2">\r\n<h6 class="mb-0"><button class="btn btn-link text-dark" data-toggle="collapse" data-target="#urologyCollapse3" aria-expanded="false" aria-controls="urologyCollapse3"> Can recurrent stones be prevented? </button></h6>\r\n</div>\r\n<div id="urologyCollapse3" class="collapse" aria-labelledby="faq3" data-parent="#urologyFaqAccordion">\r\n<div class="card-body text-dark">Yes, with dietary and medical advice.</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Bootstrap 4.5 JS dependencies -->','\r',char(13)),'\n',char(10)),13,1,'fa-kidneys','bg-indigo-50','text-indigo-100','from-blue-500 to-indigo-600',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,1,NULL,'2026-06-27 04:42:58','2026-06-27 09:56:41','<ul><li>Kidney stone removal (PCNL, ureteroscopy)</li><li>Prostate surgery (TURP, laser)</li><li>Bladder surgery</li><li>Urethral reconstruction</li><li>Male infertility treatment</li></ul>','<ul><li>Kidney & bladder stones</li><li>Prostate enlargement (BPH)</li><li>Urinary incontinence</li><li>Urinary tract infections</li><li>Male infertility</li></ul>','<ul><li>Prostate Health Check</li><li>Kidney Stone Prevention Program</li><li>Male Fertility Evaluation Package</li></ul>',NULL,NULL,'[{"question":"Do you treat female urinary issues?","answer":"Yes, including incontinence."},{"question":"Is laser surgery available for prostate?","answer":"Yes, minimally invasive options are available."},{"question":"Can recurrent stones be prevented?","answer":"Yes, with dietary and medical advice."}]');
