INSERT INTO doctors VALUES(23,10,'Dr. Abeda Khatun','dr.-abeda-khatun','Gynecologist and obstetrician','DGO, MRCOG (London), FRCOG (London), FACOG','Senior Consultant Obstetrician & Gynaecologist. Laparoscopic Surgeon','AMZ Hospital Ltd.',replace(replace('<p>Dr. Abeda Khatun graduated from Rajshahi Medical College in 1975. She had a long career in the field of Obstetrics and Gynaecology. She started her career in Obs &amp; Gynae in 1977 at Holy Family Hospital, Dhaka, and completed a Diploma in Obstetrics and Gynaecology (DGO) in 1983 from Riyadh Maternity and Children''s Hospital, Riyadh, Saudi Arabia. The DGO course was organized by the Ministry of Health, Kingdom of Saudi Arabia, jointly with the University of London, UK. After completing the DGO, she worked at the Maternity and Children''s Hospital, one of the largest tertiary care centers in Saudi Arabia, with an average of 24,000 deliveries per annum. She was posted at King Khaled Hospital in 1985, Al Kharj, and worked until 1989. It was a newly built 200-bed general hospital with 50 beds in the Obs &amp; Gynae department. In 1989, she joined Al Yamamah Maternity and Children''s Hospital, a 300-bed hospital with a very busy Obs &amp; Gynae unit, attaining an average of 15,000 deliveries per annum.</p>\r\n<p>In 1997, she moved to the United Kingdom and joined Whipps Cross Hospital, London. In 2003, she passed the MRCOG (UK) and returned to Riyadh, joining Al Obeid Specialized Hospital, Riyadh, working as a senior Consultant Obstetrician and Gynaecologist until 2021. She secured FRCOG in 2014 and FACOG in the same year. During her career, she has gained expertise and specialized training in the following fields of Obs &amp; Gynae:</p>\r\n<ul>\r\n<li>✔ IVF-ET with assisted fertility at King Faisal Specialist Hospital and Research Center, Riyadh, Saudi Arabia.</li>\r\n<li>✔ Gynaecological and Obstetrical Ultrasound at Maternity and Children''s Hospital, Riyadh, KSA.</li>\r\n<li>✔ Advanced Laparoscopic surgery, Level-IV in animals, King Fahad National Guard Hospital, Riyadh, KSA.</li>\r\n<li>✔ Laparoscopy &amp; Hysteroscopy Workshop, Military Hospital, Riyadh, KSA.</li>\r\n<li>✔ Colposcopy &amp; Cytology Workshop, King Fahad Medical City, KSA.</li>\r\n<li>&nbsp;</li>\r\n</ul>\r\n<p>She is highly experienced in all types of Obstetrics and Gynaecological surgery, especially Laparoscopic gynaecological interventions. Dr. Abeda attended many Obs. &amp; Gynae seminars, and she has many publications in journals of Obs &amp; Gynaecology.</p>','\r',char(13)),'\n',char(10)),'NB-1507',1000,NULL,'1847331002',NULL,'NULL',NULL,NULL,0,1,0,0,NULL,NULL,NULL,NULL,NULL,1,1,1,'2026-06-27 04:42:58','2026-06-29 06:43:01');
INSERT INTO doctors VALUES(39,18,'Prof. Dr. Saeedur Rahman','prof.-dr.-saeedur-rahman','Pediatric specialist','MBBS (DMC), FCPS (Pediatrics)','Senior Consultant','AMZ Hospital Ltd. (Pediatrician)',replace(replace('<p>As a Specialist Physician in Pediatrics and Neonatology he has gained a diversified experience and cross-functional expertise by working and living in 3 different countries: Bangladesh, Iran &amp; Saudi Arabia. He wants to serve the pediatric age group of patients sincerely and wholeheartedly with devotion with his knowledge and skills that he acquired in the last 39 years in the field of pediatrics, both at home and abroad.</p>\r\n<p>Prof. Dr. Saeedur Rahman completed his graduation (MBBS) from Dhaka Medical College in the year 1980.</p>\r\n<p>Thereafter he has served as Health Cadre, Bangladesh Civil Service from year 1981 till year 1990, he was a lecturer of Pathology at Sylhet Medical College and Hospital for a year.</p>\r\n<p>He achieved his FCPS from Bangladesh College of Physicians &amp; Surgeons in the year 1989.</p>\r\n<p>From year 1990 till year 1991 he was a Senior Registrar, Pediatrics at Dhaka Shishu (Children) Hospital.</p>\r\n<p>In the year 1991 he joined Ministry of Health, Islamic Republic of Iran as a Pediatric Specialist and served in three different district hospitals till year 1993.&nbsp;</p>\r\n<p>He has also worked as a Professor, Pediatric Consultant &amp; Head of the Department of Pediatrics at Jahurul Islam Medical College &amp; Hospital for 13 long years from 1994 till 2007.</p>\r\n<p>Then he joined United Hospital Ltd. as a Pediatric Consultant and worked there from year 2007 till year 2008.</p>\r\n<p>Then he joined Al-Qunfudah General Hospital as a Pediatric Specialist in Kingdom of Saudi Arabia and worked from year 2008 till year 2018.</p>\r\n<p>Upon his return from Kingdom of Saudi Arabia he joined as a Senior Consultant, Pediatrics at BRB Hospital Limited and served there from year 2018 till year 2021.</p>\r\n<p>Currently he has joined AMZ Hospital Limited as Senior Consultant, Pediatric from year 2021 and ever since he has been treating patients delicately.</p>\r\n<p>&nbsp;</p>','\r',char(13)),'\n',char(10)),'NB-1502',1000,NULL,'1847331012',NULL,'S00113',NULL,NULL,0,1,0,0,NULL,NULL,NULL,NULL,NULL,1,1,1,'2026-06-27 04:42:58','2026-06-29 06:50:12');
